let _usersCache=null;
function loadUsers(){return _usersCache||DEFAULT_USERS;}
function saveUsers(users){_usersCache=users;try{fetch('/api/users',{method:'POST',headers:{'Content-Type':'application/json'},body:JSON.stringify(users)});}catch(e){}}
async function fetchUsers(){try{const r=await fetch('/api/users');if(r.ok)_usersCache=await r.json();}catch(e){}_usersCache=_usersCache||DEFAULT_USERS;}

let CURRENT=null; // utilisateur connecté

async function doLogin(){
  const uid=document.getElementById('login-user').value.trim().toLowerCase();
  const pwd=document.getElementById('login-pass').value;
  // Étape 1 : authentification uniquement
  let user;
  try{
    const r=await fetch('/api/login',{method:'POST',headers:{'Content-Type':'application/json'},body:JSON.stringify({uid,pwd})});
    if(!r.ok){document.getElementById('login-err').style.display='block';document.getElementById('login-pass').value='';return;}
    ({user}=await r.json());
  }catch(e){console.error('Erreur login:',e);document.getElementById('login-err').style.display='block';return;}
  // Étape 2 : initialisation (erreur séparée du login)
  CURRENT={...user};
  applyProfile();
  try{await fetchUsers();}catch(e){console.error('fetchUsers:',e);}
  try{await initApp();}catch(e){console.error('initApp:',e);}
  document.getElementById('login-overlay').style.display='none';
}
function doLogout(){
  fetch('/api/logout',{method:'POST'}).catch(()=>{});
  CURRENT=null;
  document.getElementById('login-overlay').style.display='flex';
  document.getElementById('login-user').value='';
  document.getElementById('login-pass').value='';
  document.getElementById('session-info').style.display='none';
  calRows=[];calState={};
}

// Sites accessibles par l'utilisateur connecté
function getUserSites(){
  if(!CURRENT)return[];
  if(CURRENT.role==='admin')return db.sites; // admin voit tout
  return [...(CURRENT.sites||[]),...(CURRENT.sitesExtra||[])];
}

function applyProfile(){
  if(!CURRENT)return;
  const isAdmin=CURRENT.role==='admin';
  // Badge rôle
  const rb=document.getElementById('role-badge');
  rb.textContent=isAdmin?'Admin':'Site';
  rb.className='role-badge '+(isAdmin?'rb-admin':'rb-site');
  // Session info
  document.getElementById('session-info').style.display='flex';
  document.getElementById('session-label').textContent=CURRENT.label;
  // Tags sites actifs dans header
  const sitesDiv=document.getElementById('active-sites-hdr');
  if(!isAdmin){
    const allSites=getUserSites();
    sitesDiv.innerHTML=allSites.map(s=>`<span class="site-tag">${s}</span>`).join('');
  } else sitesDiv.innerHTML='';
  // Onglets selon rôle
  document.getElementById('tab-kpi').style.display=''; // tous voient les KPIs (filtrés)
  document.getElementById('tab-export').style.display=isAdmin?'':'none';
  var tabEvo=document.getElementById('tab-evolution');
  var tabSim=document.getElementById('tab-simulation');
  if(tabEvo)tabEvo.style.display=isAdmin?'':'none';
  if(tabSim)tabSim.style.display=isAdmin?'':'none'; // export admin seulement
}

