let _saveTimer=null;
function save(){
  if(_saveTimer)clearTimeout(_saveTimer);
  _saveTimer=setTimeout(()=>{
    fetch('/api/data',{method:'POST',headers:{'Content-Type':'application/json'},body:JSON.stringify(db)})
      .then(r=>{if(r.status===401)doLogout();})
      .catch(()=>{});
  },300);
}
function saveNow(){
  if(_saveTimer){clearTimeout(_saveTimer);_saveTimer=null;}
  return fetch('/api/data',{method:'POST',headers:{'Content-Type':'application/json'},body:JSON.stringify(db)})
    .then(r=>{if(r.status===401)doLogout();})
    .catch(()=>{});
}

// ── Helpers ───────────────────────────────────────────────────────────────────
function fmtH(h){if(!h||h<=0)return'—';const hh=Math.floor(h);const mm=Math.round((h-hh)*60);return hh+'h'+(mm?String(mm).padStart(2,'0'):'00');}
function fmtE(v){if(!v||v<=0)return'—';return v.toLocaleString('fr-FR',{minimumFractionDigits:2,maximumFractionDigits:2})+' €';}
function calcH(deb,fin,p=30){if(!deb||!fin)return 0;const[dh,dm]=deb.split(':').map(Number);const[fh,fm]=fin.split(':').map(Number);let m=(fh*60+fm)-(dh*60+dm)-(parseInt(p)||0);if(m<0)m+=1440;return Math.max(0,m/60);}
function weekKey(d){const dt=new Date(d);const day=dt.getDay();const diff=dt.getDate()-day+(day===0?-6:1);const mon=new Date(dt);mon.setDate(diff);return mon.toISOString().slice(0,10);}
function weekKeyLabel(wk){const mon=new Date(wk);const sun=new Date(mon);sun.setDate(mon.getDate()+6);const fmt=x=>x.toLocaleDateString('fr-FR',{day:'2-digit',month:'2-digit'});const wn=Math.ceil((mon-new Date(mon.getFullYear(),0,4))/604800000)+1;return'S'+wn+' ('+fmt(mon)+'–'+fmt(sun)+')';}
function moisLabel(ym){if(!ym)return'';const[y,m]=ym.split('-');return new Date(y,m-1,1).toLocaleDateString('fr-FR',{month:'long',year:'numeric'});}
function getMoisList(){const s=new Set(db.entries.map(e=>e.date.slice(0,7)));s.add(new Date().toISOString().slice(0,7));return[...s].sort((a,b)=>b.localeCompare(a));}
function statusBadge(st){if(st==='validated')return'<span class="badge b-ok">Validée</span>';if(st==='rejected')return'<span class="badge b-rej">Refusée</span>';return'<span class="badge b-att">En attente</span>';}
function initials(n){return n.split(' ').map(w=>w[0]||'').join('').slice(0,2).toUpperCase();}
function genId(){return Date.now()+Math.random();}
function updatePendingBadge(){
  const sites=getUserSites();
  const n=db.entries.filter(e=>e.status==='pending'&&(CURRENT?.role==='admin'||sites.includes(e.agence))).length;
  const hp=document.getElementById('hdr-pending');
  if(n>0){hp.style.display='flex';document.getElementById('hdr-badge').textContent=n;}else hp.style.display='none';
}

// Filtre les entrées selon le profil connecté
function filterByProfile(entries){
  if(!CURRENT||CURRENT.role==='admin')return entries;
  const sites=getUserSites();
  return entries.filter(e=>sites.includes(e.site)); // agence = site Distritec ici
}

function goTab(id,btn){
  document.querySelectorAll('.dtab').forEach(b=>b.classList.remove('active'));
  document.querySelectorAll('.sec').forEach(s=>s.classList.remove('active'));
  btn.classList.add('active');document.getElementById(id).classList.add('active');
  const bar=document.getElementById('submit-bar');
  if(bar){if(id==='saisie'){bar.classList.add('visible');updateSubmitCount();}else{bar.classList.remove('visible','active');}}
  if(id==='validation')renderValidation();
  if(id==='kpi'){populateKpiFilters();renderKpi();}
  if(id==='listing')renderList();
  if(id==='declaratif')renderDecl();
  if(id==='params')renderParams();
  if(id==='export')syncExpFilters();
  if(id==='evolution'){initEvoFilters();renderEvolution();}
  if(id==='simulation'){initSimFilters();renderSimulation();}
}

function populateSiteAct(){
  const sites=getUserSites();
  const so=sites.map(s=>`<option>${s}</option>`).join('');
  document.getElementById('t-site').innerHTML='<option value="">— Sélectionner —</option>'+so;
  // t-act-global supprimé de la toolbar
}
function populateMoisSelects(ids){
  const ml=getMoisList();const opts=ml.map(m=>`<option value="${m}">${moisLabel(m)}</option>`).join('');
  ids.forEach(id=>{const el=document.getElementById(id);if(el){const cur=el.value;el.innerHTML=opts;if(cur)el.value=cur;}});
}
function syncSiteFilters(ids){
  const sites=CURRENT?.role==='admin'?[...new Set(db.entries.map(e=>e.site))].sort():getUserSites();
  const opts='<option value="">Tous les sites</option>'+sites.map(s=>`<option>${s}</option>`).join('');
  ids.forEach(id=>{const el=document.getElementById(id);if(el){const c=el.value;el.innerHTML=opts;if(c)el.value=c;}});
}
function showAddAlert(msg,t){const el=document.getElementById('add-alert');el.className='alert alert-'+t;el.textContent=msg;el.style.display='block';setTimeout(()=>el.style.display='none',3500);}
function showCalAlert(msg,t){const el=document.getElementById('cal-alert');el.className='alert alert-'+t;el.textContent=msg;el.style.display='block';setTimeout(()=>el.style.display='none',4000);}

async function initApp(){
  await load();
  populateSiteAct();
  populateMoisSelects(['v-mois','l-mois','d-mois']);
  syncSiteFilters(['v-site','l-site','d-site']);
  updatePendingBadge();
  populateAgenceSelect();
  render();
  // Si site unique : pré-sélectionner
  const sites=getUserSites();
  if(sites.length===1)document.getElementById('t-site').value=sites[0];
}

// ── Mini calendrier ───────────────────────────────────────────────────────────
function getMon(d){const dt=new Date(d);const day=dt.getDay();const diff=dt.getDate()-day+(day===0?-6:1);dt.setDate(diff);dt.setHours(0,0,0,0);return new Date(dt);}
function addDays(d,n){const r=new Date(d);r.setDate(r.getDate()+n);return r;}
function fmtD(d){return d.toLocaleDateString('fr-FR',{day:'2-digit',month:'2-digit'});}
function fmtIso(d){return`${d.getFullYear()}-${String(d.getMonth()+1).padStart(2,'0')}-${String(d.getDate()).padStart(2,'0')}`;}
function isToday(d){const t=new Date();return d.getFullYear()===t.getFullYear()&&d.getMonth()===t.getMonth()&&d.getDate()===t.getDate();}
function getWkN(d){const mon=getMon(d);return Math.ceil((mon-new Date(mon.getFullYear(),0,4))/604800000)+1;}
function prevW(){currentMon=addDays(currentMon,-7);render();}
function nextW(){currentMon=addDays(currentMon,7);render();}
function goNow(){currentMon=getMon(new Date());render();}
function toggleMiniCal(){const p=document.getElementById('mini-cal');p.classList.contains('open')?closeMiniCal():(mcYear=currentMon.getFullYear(),mcMonth=currentMon.getMonth(),renderMiniCal(),p.classList.add('open'));}
function closeMiniCal(){document.getElementById('mini-cal').classList.remove('open');}
function mcPrevM(){mcMonth--;if(mcMonth<0){mcMonth=11;mcYear--;}renderMiniCal();}
function mcNextM(){mcMonth++;if(mcMonth>11){mcMonth=0;mcYear++;}renderMiniCal();}
function renderMiniCal(){const MOIS=['Janvier','Février','Mars','Avril','Mai','Juin','Juillet','Août','Septembre','Octobre','Novembre','Décembre'];document.getElementById('mc-tit').textContent=MOIS[mcMonth]+' '+mcYear;const grid=document.getElementById('mc-grid');grid.innerHTML='';['L','M','M','J','V','S','D'].forEach(d=>{const div=document.createElement('div');div.className='mc-dh';div.textContent=d;grid.appendChild(div);});const firstDay=new Date(mcYear,mcMonth,1).getDay();const offset=(firstDay===0)?6:firstDay-1;const dim=new Date(mcYear,mcMonth+1,0).getDate();const today=new Date();const curWk=getMon(currentMon).toISOString().slice(0,10);for(let i=0;i<offset;i++){const div=document.createElement('div');div.className='mc-d';grid.appendChild(div);}for(let d=1;d<=dim;d++){const dt=new Date(mcYear,mcMonth,d);const div=document.createElement('div');div.textContent=d;div.className='mc-d';if(dt.getFullYear()===today.getFullYear()&&dt.getMonth()===today.getMonth()&&dt.getDate()===today.getDate())div.classList.add('today');if(getMon(dt).toISOString().slice(0,10)===curWk)div.classList.add('in-week');div.onclick=()=>{currentMon=getMon(dt);render();closeMiniCal();};grid.appendChild(div);}}
document.addEventListener('click',function(e){if(!document.getElementById('week-nav-wrap')?.contains(e.target))closeMiniCal();const drop=document.getElementById('ac-dropdown');if(!document.getElementById('f-nom')?.contains(e.target)&&!drop?.contains(e.target))drop.style.display='none';});
function onSiteChange(){render();}

// ── Agence & Autocomplete ──────────────────────────────────────────────────────
function populateAgenceSelect(){document.getElementById('f-agence').innerHTML='<option value="">— Sélectionner —</option>'+db.agences.map(a=>`<option>${a}</option>`).join('');}
function onAgenceChange(){
  const ag=document.getElementById('f-agence')?.value||'';
  const wrap=document.getElementById('f-agence-autre-wrap');
  if(wrap)wrap.style.display=ag==='Autre'?'':'none';
  if(ag!=='Autre'){const f=document.getElementById('f-agence-autre');if(f)f.value='';}
  document.getElementById('f-nom').value='';
  document.getElementById('f-taux').value='';
  const hintNew=document.getElementById('hint-new');if(hintNew)hintNew.style.display='none';
  const acDrop=document.getElementById('ac-dropdown');if(acDrop)acDrop.style.display='none';
  renderMemoZone();
}
function removeRow(id){calRows=calRows.filter(r=>r.id!=id);delete calState[id];render();}
function toggleCell(id,day){
  const s=getS(id,day);const key=`${id}_${day}`;
  const debEl=document.getElementById('deb-'+key);const finEl=document.getElementById('fin-'+key);const pauEl=document.getElementById('pau-'+key);
  const deb=debEl?debEl.value:'08:00';const fin=finEl?finEl.value:'17:00';const pause=pauEl?parseInt(pauEl.value)||30:30;
  const isChecked=s?s.checked:false;setS(id,day,{checked:!isChecked,deb,fin,pause});
  const chk=document.getElementById('chk-'+key);const lbl=chk?chk.nextElementSibling:null;
  if(chk){chk.className='chkbox'+(!isChecked?' on':'');chk.textContent=!isChecked?'✓':'';}
  if(lbl){lbl.className='toggle-lbl '+(!isChecked?'on':'off');lbl.textContent=!isChecked?'Travaillé':'Absent';}
  if(debEl)debEl.disabled=isChecked;if(finEl)finEl.disabled=isChecked;if(pauEl)pauEl.disabled=isChecked;
  const res=document.getElementById('res-'+key);if(res)res.textContent=!isChecked?fmtH(calcH(deb,fin,pause)):'—';
  updateLineTotals(id);updateColTotals();updateSubmitCount();
}
function onTC(id,day){
  const key=`${id}_${day}`;const deb=document.getElementById('deb-'+key).value;const fin=document.getElementById('fin-'+key).value;const pause=parseInt(document.getElementById('pau-'+key).value)||0;
  if(!calState[id])calState[id]={};if(!calState[id][day])calState[id][day]={checked:true,deb,fin,pause};else Object.assign(calState[id][day],{deb,fin,pause});
  const res=document.getElementById('res-'+key);if(res&&deb&&fin)res.textContent=fmtH(calcH(deb,fin,pause));
  updateLineTotals(id);updateColTotals();updateSubmitCount();
}
function updateLineTotals(id){const row=calRows.find(r=>r.id==id);if(!row)return;let h=0,cout=0;for(let i=0;i<5;i++){const s=getS(id,i);if(s&&s.checked){const dh=calcH(s.deb,s.fin,s.pause);h+=dh;cout+=dh*row.taux;}}const tH=document.getElementById('toth-'+id);const tC=document.getElementById('totc-'+id);if(tH)tH.textContent=fmtH(h);if(tC)tC.textContent=fmtE(cout);}
function updateColTotals(){const rows=document.querySelectorAll('#cal-body tr.row-total');if(!rows.length)return;const cells=rows[0].querySelectorAll('td');let gH=0,gC=0;for(let i=0;i<5;i++){let cH=0,cC=0;calRows.forEach(row=>{const s=getS(row.id,i);if(s&&s.checked){const h=calcH(s.deb,s.fin,s.pause);cH+=h;cC+=h*row.taux;}});gH+=cH;gC+=cC;if(cells[i+1])cells[i+1].innerHTML=cH>0?`<span style="color:var(--green)">${fmtH(cH)}</span><br><span style="font-size:9px;color:var(--blue)">${fmtE(cC)}</span>`:'<span style="color:#CCC">—</span>';}if(cells[6])cells[6].textContent=fmtH(gH);if(cells[7])cells[7].textContent=fmtE(gC);}
function updateSubmitCount(){
  let n=0;calRows.forEach(row=>{for(let i=0;i<5;i++){const s=getS(row.id,i);if(s&&s.checked)n++;}});
  document.getElementById('nb-entries').textContent=n;
  const btn=document.getElementById('btn-submit');
  const bar=document.getElementById('submit-bar');
  const lbl=document.getElementById('submit-bar-label');
  btn.disabled=n===0;
  // Barre visible seulement sur l'onglet Saisie
  const onSaisie=document.getElementById('saisie')?.classList.contains('active');
  if(onSaisie){
    bar.classList.add('visible');
    if(n>0){
      bar.classList.add('active');
      lbl.style.color='var(--green)';
      lbl.textContent=`${n} journée(s) prête(s) à soumettre`;
    } else {
      bar.classList.remove('active');
      lbl.style.color='var(--muted)';
      lbl.textContent='Cochez des journées dans la grille pour soumettre';
    }
  } else {
    bar.classList.remove('visible');
  }
}
function applyRef(){const deb=document.getElementById('t-deb').value;const fin=document.getElementById('t-fin').value;const pause=parseInt(document.getElementById('t-pause').value)||30;if(!deb||!fin){showCalAlert('Renseigne l\'horaire.','err');return;}let count=0;calRows.forEach(row=>{for(let i=0;i<5;i++){const key=`${row.id}_${i}`;const chk=document.getElementById('chk-'+key);if(chk&&chk.classList.contains('on')){setS(row.id,i,{checked:true,deb,fin,pause});const debEl=document.getElementById('deb-'+key);const finEl=document.getElementById('fin-'+key);const pauEl=document.getElementById('pau-'+key);if(debEl)debEl.value=deb;if(finEl)finEl.value=fin;if(pauEl)pauEl.value=pause;const res=document.getElementById('res-'+key);if(res)res.textContent=fmtH(calcH(deb,fin,pause));updateLineTotals(row.id);count++;}}});updateColTotals();updateSubmitCount();if(count)showCalAlert(`Horaire ${deb}–${fin} (${pause}min) sur ${count} cellule(s).`,'ok');else showCalAlert('Aucune cellule cochée.','err');}
function submitAll(){
  const site=document.getElementById('t-site').value;if(!site){showCalAlert('Merci de sélectionner un site.','err');return;}
  const agVal=document.getElementById('f-agence')?.value;
  if(agVal==='Autre'&&!document.getElementById('f-agence-autre')?.value?.trim()){
    showCalAlert("Merci de préciser le nom de l'agence.",'err');return;
  }
  const noAct=calRows.filter(r=>!r.act);if(noAct.length){showCalAlert(`${noAct.length} intérimaire(s) sans poste occupé.`,'err');return;}
  let added=0;calRows.forEach(row=>{for(let i=0;i<5;i++){const s=getS(row.id,i);if(!s||!s.checked)continue;const date=fmtIso(addDays(currentMon,i));const h=calcH(s.deb,s.fin,s.pause);const wk=weekKey(date);const wkKey2=site+'|'+wk;if(db.weekValidations[wkKey2]?.status==='validated')db.weekValidations[wkKey2]={status:'pending'};db.entries.push({id:genId(),nom:row.nom,agence:(row.agence==='Autre'&&document.getElementById('f-agence-autre')?.value?.trim()?document.getElementById('f-agence-autre').value.trim():row.agence),site,date,deb:s.deb,fin:s.fin,pause:s.pause||0,h:parseFloat(h.toFixed(4)),act:row.act,taux:row.taux,cout:parseFloat((h*row.taux).toFixed(2)),obs:'',status:'pending',wk});added++;}});
  if(!added){showCalAlert('Aucune cellule cochée.','err');return;}
  save();populateMoisSelects(['v-mois','l-mois','d-mois']);syncSiteFilters(['v-site','l-site','d-site']);updatePendingBadge();
  showCalAlert(`✓ ${added} entrée(s) soumises — ${site}`,'ok');calRows.forEach(r=>{calState[r.id]={};});render();
}

function render(){
  const wn=getWkN(currentMon);document.getElementById('wk-lbl').textContent=`S${wn}  —  ${fmtD(currentMon)} › ${fmtD(addDays(currentMon,4))}`;
  if(document.getElementById('mini-cal').classList.contains('open'))renderMiniCal();
  const rD=document.getElementById('row-days'),rS=document.getElementById('row-sub');
  while(rD.children.length>1)rD.removeChild(rD.lastChild);while(rS.children.length>1)rS.removeChild(rS.lastChild);
  for(let i=0;i<5;i++){const d=addDays(currentMon,i);const isT=isToday(d);const th=document.createElement('th');th.className=isT?'today-hd':'';th.innerHTML=`<div class="day-th-name">${DAYS[i]}</div><span class="day-th-date">${fmtD(d)}</span>`;rD.appendChild(th);const ths=document.createElement('th');ths.className=isT?'today-hd':'';ths.textContent='Début · Fin · Pause';rS.appendChild(ths);}
  [{t:'Total H.',bg:'#2A2727'},{t:'Coût',bg:'#1A2A3A'}].forEach(({t,bg})=>{const th=document.createElement('th');th.textContent=t;th.style.cssText=`background:${bg};color:white;padding:9px 6px;text-align:center;font-size:11px;font-weight:700`;rD.appendChild(th);const ths=document.createElement('th');ths.textContent='Semaine';rS.appendChild(ths);});
  const body=document.getElementById('cal-body');body.innerHTML='';
  if(!calRows.length){const tr=document.createElement('tr');const td=document.createElement('td');td.setAttribute('colspan','8');td.innerHTML='<p class="empty" style="padding:1.5rem">Aucun intérimaire — ajoutez-en ci-dessus.</p>';tr.appendChild(td);body.appendChild(tr);updateSubmitCount();return;}
  calRows.forEach(row=>{
    const tr=document.createElement('tr');const tdN=document.createElement('td');tdN.className='interim-cell';
    tdN.innerHTML=`<div class="interim-top"><div class="avatar">${initials(row.nom)}</div><div><div style="font-size:11px;font-weight:700">${row.nom}</div><div style="display:flex;align-items:center;gap:6px;margin-top:2px"><span class="badge b-ag" style="font-size:9px">${row.agence}</span><input type="text" id="taux-${row.id}" value="${row.taux.toFixed(2)}" inputmode="decimal" onchange="updateRowTaux('${row.id}',this.value)" style="width:50px;height:20px;font-size:10px;font-weight:700;text-align:center;border:1px solid #DBEAFE;border-radius:3px;color:var(--blue);background:#F0F6FF" title="Taux horaire modifiable"/> <span style="font-size:9px;color:var(--muted)">€/h</span></div></div><button class="btn-del" onclick="removeRow('${row.id}')" style="margin-left:auto">×</button></div><div class="row-act-select"><select id="act-sel-${row.id}" onchange="onRowActChange('${row.id}',this)">${getRowActOpts(row.act)}</select></div>`;
    tr.appendChild(tdN);let wH=0,wC=0;
    for(let i=0;i<5;i++){const d=addDays(currentMon,i);const isT=isToday(d);const s=getS(row.id,i);const checked=s?s.checked:false;const deb=s?s.deb:'08:00';const fin=s?s.fin:'17:00';const pause=s!=null?s.pause:30;const h=checked?calcH(deb,fin,pause):0;if(checked){wH+=h;wC+=h*row.taux;}const key=`${row.id}_${i}`;const td=document.createElement('td');td.className='day-cell'+(isT?' today-col':'');td.innerHTML=`<div><div class="cell-toggle" onclick="toggleCell('${row.id}',${i})"><div class="chkbox${checked?' on':''}" id="chk-${key}">${checked?'✓':''}</div><span class="toggle-lbl ${checked?'on':'off'}">${checked?'Travaillé':'Absent'}</span></div><div class="cell-times"><input type="time" id="deb-${key}" value="${deb}" ${checked?'':'disabled'} oninput="onTC('${row.id}',${i})"/><input type="time" id="fin-${key}" value="${fin}" ${checked?'':'disabled'} oninput="onTC('${row.id}',${i})"/><div class="pause-row"><input type="text" inputmode="numeric" id="pau-${key}" value="${pause}" ${checked?'':'disabled'} oninput="onTC('${row.id}',${i})" style="text-align:center"/><span class="pause-lbl">min</span></div></div><div class="cell-result" id="res-${key}">${checked?fmtH(h):'—'}</div></div>`;tr.appendChild(td);}
    const tdT=document.createElement('td');tdT.className='total-cell';tdT.innerHTML=`<div class="tot-h" id="toth-${row.id}">${fmtH(wH)}</div><div class="tot-c" id="totc-${row.id}">${fmtE(wC)}</div>`;tr.appendChild(tdT);const tdC=document.createElement('td');tdC.style.display='none';tr.appendChild(tdC);body.appendChild(tr);
  });
  const trTot=document.createElement('tr');trTot.className='row-total';const tdL=document.createElement('td');tdL.className='lbl-col';tdL.textContent='Total / jour';trTot.appendChild(tdL);let gH=0,gC=0;
  for(let i=0;i<5;i++){let cH=0,cC=0;calRows.forEach(row=>{const s=getS(row.id,i);if(s&&s.checked){const h=calcH(s.deb,s.fin,s.pause);cH+=h;cC+=h*row.taux;}});gH+=cH;gC+=cC;const td=document.createElement('td');td.innerHTML=cH>0?`<span style="color:var(--green)">${fmtH(cH)}</span><br><span style="font-size:9px;color:var(--blue)">${fmtE(cC)}</span>`:'<span style="color:#CCC">—</span>';trTot.appendChild(td);}
  const tdGH=document.createElement('td');tdGH.style.cssText='font-size:13px;font-weight:800;color:var(--green)';tdGH.textContent=fmtH(gH);trTot.appendChild(tdGH);const tdGC=document.createElement('td');tdGC.style.cssText='font-size:11px;font-weight:700;color:var(--blue)';tdGC.textContent=fmtE(gC);trTot.appendChild(tdGC);body.appendChild(trTot);updateSubmitCount();
}

// ══════════════════════════════════════════════════════════════════════════════
// VALIDATION
// ══════════════════════════════════════════════════════════════════════════════
function renderValidation(){
  syncSiteFilters(['v-site']);
  const mois=document.getElementById('v-mois').value,site=document.getElementById('v-site').value,statut=document.getElementById('v-statut').value;
  const agenceV=document.getElementById('v-agence')?.value||'';
  (function(){const ags=[...new Set(db.entries.map(e=>e.agence))].sort();const el=document.getElementById('v-agence');if(el){const c=el.value;el.innerHTML='<option value="">Toutes agences</option>'+ags.map(a=>`<option>${a}</option>`).join('');if(c)el.value=c;}})();
  let data=filterByProfile(db.entries).filter(e=>(!mois||e.date.startsWith(mois))&&(!site||e.site===site)&&(!agenceV||e.agence===agenceV));
  const grouped={};
  data.forEach(e=>{const k=e.site+'|'+e.wk;if(!grouped[k])grouped[k]={site:e.site,wk:e.wk,entries:[]};grouped[k].entries.push(e);});
  let nbA=0,nbO=0,nbR=0;
  Object.keys(grouped).forEach(k=>{const ws=db.weekValidations[k]||{status:'pending'};if(ws.status==='pending')nbA++;else if(ws.status==='validated')nbO++;else nbR++;});
  document.getElementById('v-nb-att').textContent=nbA;
  document.getElementById('v-nb-ok').textContent=nbO;
  document.getElementById('v-nb-rej').textContent=nbR;
  const filtered=Object.keys(grouped).filter(k=>!statut||(db.weekValidations[k]||{status:'pending'}).status===statut)
    .sort((a,b)=>{const[,wa]=a.split('|');const[,wb]=b.split('|');return wb.localeCompare(wa)||a.localeCompare(b);});
  if(!filtered.length){document.getElementById('v-content').innerHTML='<p class="empty">Aucune semaine.</p>';return;}

  document.getElementById('v-content').innerHTML=filtered.map(k=>{
    const g=grouped[k];
    const ws=db.weekValidations[k]||{status:'pending'};
    const st=ws.status;
    const tot=g.entries.reduce((s,e)=>s+e.h,0);
    const totC=g.entries.reduce((s,e)=>s+(e.cout||0),0);
    const noms=[...new Set(g.entries.map(e=>e.nom))];
    const nbInt=noms.length;
    const kSafe=k.replace(/\|/g,'__');

    // Boutons validation
    let btns=st==='pending'
      ?`<button class="btn-valid" onclick="openModal('${k}','validate')">✓ Valider</button><button class="btn-reject" onclick="openModal('${k}','reject')">✗ Refuser</button>`
      :st==='validated'
      ?`<button class="btn-unval" onclick="setStatus('${k}','pending','')">Annuler</button>`
      :`<button class="btn-valid" onclick="openModal('${k}','validate')">✓ Valider</button><button class="btn-unval" onclick="setStatus('${k}','pending','')">Remettre</button>`;

    return`<div class="scard val-${st}" id="wkcard-${kSafe}">
      <!-- EN-TÊTE SEMAINE (toujours visible) -->
      <div style="display:flex;justify-content:space-between;align-items:flex-start;gap:10px">
        <div style="flex:1;cursor:pointer" onclick="toggleWkDetail('${kSafe}')">
          <div style="display:flex;align-items:center;gap:8px;flex-wrap:wrap;margin-bottom:6px">
            <span class="badge b-site">${g.site}</span>
            <span class="badge b-week">${weekKeyLabel(g.wk)}</span>
            ${statusBadge(st)}
            <span style="font-size:11px;color:var(--muted);margin-left:4px">▸ ${nbInt} intérimaire(s)</span>
          </div>
          <!-- Résumé par intérimaire -->
          <div style="display:flex;flex-wrap:wrap;gap:6px;margin-bottom:6px">
            ${noms.map(nom=>{
              const lines=g.entries.filter(e=>e.nom===nom);
              const h=lines.reduce((s,e)=>s+e.h,0);
              const c=lines.reduce((s,e)=>s+(e.cout||0),0);
              const jours=lines.length;
              return`<div style="background:#F7F8FF;border:1px solid #DBEAFE;border-radius:6px;padding:5px 10px;font-size:11px">
                <span style="font-weight:700">${nom}</span>
                <span style="color:var(--muted);margin:0 4px">·</span>
                <span style="color:var(--green);font-weight:600">${fmtH(h)}</span>
                <span style="color:var(--muted);margin:0 4px">·</span>
                <span style="color:var(--blue);font-weight:600">${fmtE(c)}</span>
                <span style="color:var(--muted);margin-left:4px;font-size:10px">${jours}j</span>
              </div>`;
            }).join('')}
          </div>
          <div style="font-size:11px;color:var(--muted)">
            Total : <strong>${g.entries.length} entrée(s)</strong> ·
            <strong style="color:var(--green)">${fmtH(tot)}</strong> nettes ·
            <strong style="color:var(--blue)">${fmtE(totC)}</strong>
            <span style="margin-left:8px;font-size:10px;color:var(--muted)">(cliquez pour voir le détail)</span>
          </div>
          ${ws.comment?`<div style="margin-top:5px;font-size:11px;font-style:italic;color:var(--muted);background:#F7F7F7;padding:5px 9px;border-radius:5px;border-left:3px solid var(--red)">${ws.comment}</div>`:''}
          ${ws.validatedBy?`<div style="font-size:10px;color:var(--muted);margin-top:3px">Par ${ws.validatedBy} le ${ws.validatedAt}</div>`:''}
        </div>
        <div style="display:flex;gap:5px;flex-shrink:0;flex-direction:column;align-items:flex-end">
          ${btns}
        </div>
      </div>

      <!-- DÉTAIL LIGNES (masqué par défaut, dépliable) -->
      <div id="wkdetail-${kSafe}" style="display:none;margin-top:12px;border-top:1px solid var(--border);padding-top:10px">
        <div style="overflow-x:auto">
          <table style="min-width:780px">
            <thead><tr>
              <th style="min-width:90px">Date</th>
              <th style="min-width:130px">Intérimaire</th>
              <th style="min-width:90px">Agence int.</th>
              <th style="min-width:110px">Poste</th>
              <th style="min-width:90px">Plage</th>
              <th style="min-width:58px">Pause</th>
              <th style="min-width:62px">H. nettes</th>
              <th style="min-width:78px">Coût</th>
              <th style="min-width:90px"></th>
            </tr></thead>
            <tbody id="wktbody-${kSafe}">
              ${g.entries.sort((a,b)=>a.date.localeCompare(b.date)).map(e=>renderEntryRow(e,kSafe)).join('')}
            </tbody>
          </table>
        </div>
      </div>
    </div>`;
  }).join('');
}

function renderEntryRow(e, kSafe){
  const eid=e.id;
  return`<tr id="erow-${eid}" style="border-bottom:1px solid #F0F0F0">
    <td>${(e.wk||e.date).split('-').reverse().join('/')}</td>
    <td style="font-weight:600">${e.nom}</td>
    <td><span class="badge b-ag">${e.agence}</span></td>
    <td><span class="badge b-act">${e.act}</span></td>
    <td style="font-size:11px;color:var(--muted)">${e.deb}–${e.fin}</td>
    <td style="font-size:11px;color:var(--amber);text-align:center">${e.pause||0} min</td>
    <td style="font-weight:700;text-align:center">${fmtH(e.h)}</td>
    <td style="font-weight:700;color:var(--blue);text-align:right">${e.cout?fmtE(e.cout):''}</td>
    <td style="text-align:center">
      <button class="btn-sm" style="font-size:10px;height:24px;color:var(--blue);border-color:#93C5FD"
        onclick="askEditEntry(${eid},'${kSafe}')">✏ Modifier</button>
    </td>
  </tr>`;
}

function renderEntryRowEdit(e, kSafe){
  // Construit les options postes
  const actsOpts=db.acts.map(a=>`<option value="${a}"${a===e.act?' selected':''}>${a}</option>`).join('');
  const agsOpts=db.agences.map(a=>`<option value="${a}"${a===e.agence?' selected':''}>${a}</option>`).join('');
  return`<tr id="erow-${e.id}" style="background:#FFFBEB;border-bottom:2px solid #FCD34D">
    <td style="font-size:11px;color:var(--muted)">
      <input type="date" id="edit-date-${e.id}" value="${e.date}"
        style="width:120px;height:26px;font-size:10px;border:1.5px solid var(--border);border-radius:4px;padding:0 4px"/>
    </td>
    <td><input type="text" value="${e.nom}" id="edit-nom-${e.id}"
      style="width:100%;height:26px;font-size:11px;border:1.5px solid var(--border);border-radius:4px;padding:0 6px"/></td>
    <td><select id="edit-ag-${e.id}" style="width:100%;height:26px;font-size:10px;border:1.5px solid var(--border);border-radius:4px">${agsOpts}</select></td>
    <td><select id="edit-act-${e.id}" style="width:100%;height:26px;font-size:10px;border:1.5px solid var(--border);border-radius:4px">${actsOpts}</select></td>
    <td>
      <div style="display:flex;align-items:center;gap:3px">
        <input type="time" id="edit-deb-${e.id}" value="${e.deb}"
          style="width:80px;height:26px;font-size:10px;border:1.5px solid var(--border);border-radius:4px;padding:0 3px"/>
        <span style="font-size:10px;color:var(--muted)">–</span>
        <input type="time" id="edit-fin-${e.id}" value="${e.fin}"
          style="width:80px;height:26px;font-size:10px;border:1.5px solid var(--border);border-radius:4px;padding:0 3px"/>
      </div>
    </td>
    <td>
      <input type="text" inputmode="numeric" id="edit-pause-${e.id}" value="${e.pause||0}"
        style="width:48px;height:26px;font-size:11px;border:1.5px solid var(--border);border-radius:4px;text-align:center"/>
    </td>
    <td style="font-size:10px;color:var(--muted);text-align:center">calculé</td>
    <td style="font-size:10px;color:var(--muted);text-align:center">calculé</td>
    <td>
      <div style="display:flex;gap:4px;justify-content:center">
        <button class="btn-valid" style="height:24px;font-size:10px;padding:0 8px"
          onclick="saveEntryEdit(${e.id},'${kSafe}')">✓ OK</button>
        <button class="btn-sm" style="height:24px;font-size:10px"
          onclick="cancelEntryEdit(${e.id},'${kSafe}')">✗</button>
      </div>
    </td>
  </tr>`;
}

function toggleWkDetail(kSafe){
  const detail=document.getElementById('wkdetail-'+kSafe);
  if(!detail)return;
  const open=detail.style.display!=='none';
  detail.style.display=open?'none':'block';
}

function askEditEntry(eid, kSafe){
  if(!confirm('Voulez-vous vraiment modifier cette saisie ?\n\nCette action remettra la semaine en statut "En attente" si elle était validée.'))return;
  const e=db.entries.find(x=>x.id==eid);if(!e)return;
  // Remettre semaine en pending si validée
  const wkKey=e.site+'|'+e.wk;
  if(db.weekValidations[wkKey]?.status==='validated'){
    db.weekValidations[wkKey]={status:'pending',comment:'Modifié après validation',validatedBy:'',validatedAt:''};
    db.entries.forEach(en=>{if(en.site+'|'+en.wk===wkKey)en.status='pending';});
    save();updatePendingBadge();
  }
  // Remplacer la ligne par le formulaire d'édition
  const row=document.getElementById('erow-'+eid);
  if(row)row.outerHTML=renderEntryRowEdit(e,kSafe);
}

function saveEntryEdit(eid, kSafe){
  const e=db.entries.find(x=>x.id==eid);if(!e)return;
  const date=document.getElementById('edit-date-'+eid)?.value;
  const nom=document.getElementById('edit-nom-'+eid)?.value.trim();
  const ag=document.getElementById('edit-ag-'+eid)?.value;
  const act=document.getElementById('edit-act-'+eid)?.value;
  const deb=document.getElementById('edit-deb-'+eid)?.value;
  const fin=document.getElementById('edit-fin-'+eid)?.value;
  const pause=parseInt(document.getElementById('edit-pause-'+eid)?.value)||0;
  if(!date||!nom||!deb||!fin){alert('Tous les champs sont obligatoires.');return;}
  // Mise à jour
  e.date=date;e.nom=nom;e.agence=ag;e.act=act;e.deb=deb;e.fin=fin;e.pause=pause;
  e.wk=weekKey(date); // recalcul de la semaine si date changée
  e.h=parseFloat(calcH(deb,fin,pause).toFixed(4));
  e.cout=parseFloat((e.h*(e.taux||0)).toFixed(2));
  save();
  // Restituer la ligne normale
  const row=document.getElementById('erow-'+eid);
  if(row)row.outerHTML=renderEntryRow(e,kSafe);
  // Mettre à jour le résumé de la carte
  refreshWkCard(kSafe);
}

function cancelEntryEdit(eid, kSafe){
  const e=db.entries.find(x=>x.id==eid);if(!e)return;
  const row=document.getElementById('erow-'+eid);
  if(row)row.outerHTML=renderEntryRow(e,kSafe);
}

function refreshWkCard(kSafe){
  // Recalcule et met à jour le résumé de la carte sans re-render tout
  // On re-render complètement la validation pour être sûr
  renderValidation();
  // Ré-ouvrir le détail
  setTimeout(()=>{
    const detail=document.getElementById('wkdetail-'+kSafe);
    if(detail)detail.style.display='block';
  },50);
}

function openModal(wkKey,action){
  modalCtx={wkKey,action};
  const isV=action==='validate';
  document.getElementById('modal-title').textContent=isV?'Valider la semaine':'Refuser la semaine';
  document.getElementById('modal-lbl').textContent=isV?'Commentaire (optionnel)':'Motif (obligatoire)';
  const btn=document.getElementById('modal-confirm-btn');
  btn.className=isV?'btn-valid':'btn-reject';
  btn.textContent=isV?'Confirmer':'Confirmer le refus';
  document.getElementById('modal-comment').value='';
  document.getElementById('modal-bg').classList.add('open');
}
function closeModal(){document.getElementById('modal-bg').classList.remove('open');modalCtx=null;}
function confirmModal(){
  if(!modalCtx)return;
  const comment=document.getElementById('modal-comment').value.trim();
  if(modalCtx.action==='reject'&&!comment){alert('Motif obligatoire.');return;}
  setStatus(modalCtx.wkKey,modalCtx.action==='validate'?'validated':'rejected',comment);
  closeModal();
}
function setStatus(wkKey,st,comment){
  db.weekValidations[wkKey]={status:st,comment,validatedBy:CURRENT?.label||'Responsable',validatedAt:new Date().toLocaleDateString('fr-FR')};
  db.entries.forEach(e=>{if(e.site+'|'+e.wk===wkKey)e.status=st;});
  save();updatePendingBadge();renderValidation();
}

// ══════════════════════════════════════════════════════════════════════════════
// KPIs — filtrés selon le profil
// ══════════════════════════════════════════════════════════════════════════════
// ── Granularité KPI ───────────────────────────────────────────────────────────
let kpiGran='mois'; // 'jour' | 'semaine' | 'mois'

function setKpiGran(g){
  kpiGran=g;
  // Boutons actifs
  ['jour','semaine','mois'].forEach(k=>{
    const btn=document.getElementById('kg-'+k);
    if(btn){btn.style.background=k===g?'var(--red)':'#F7F7F7';btn.style.color=k===g?'white':'var(--muted)';}
  });
  // Panneaux
  document.getElementById('k-filter-jour').style.display=g==='jour'?'flex':'none';
  document.getElementById('k-filter-semaine').style.display=g==='semaine'?'flex':'none';
  document.getElementById('k-filter-mois').style.display=g==='mois'?'flex':'none';
  renderKpi();
}

function populateKpiFilters(){
  const isAdmin=CURRENT?.role==='admin';
  document.getElementById('kpi-title').textContent=isAdmin?'KPIs — Vue globale':'KPIs — '+CURRENT?.label;
  document.getElementById('k-global-section').style.display=isAdmin?'':'none';

  // Années disponibles
  const years=[...new Set(db.entries.map(e=>e.date.slice(0,4)))].sort((a,b)=>b-a);
  const cur=new Date().getFullYear().toString();if(!years.includes(cur))years.unshift(cur);
  const elY=document.getElementById('k-annee');const pY=elY.value;
  elY.innerHTML=years.map(y=>`<option value="${y}">${y}</option>`).join('');
  if(pY&&years.includes(pY))elY.value=pY;

  // Mois disponibles (pour filtre mois unique)
  const moisDispo=[...new Set(db.entries.map(e=>e.date.slice(0,7)))].sort((a,b)=>b.localeCompare(a));
  const elM=document.getElementById('k-mois-unique');const pM=elM.value;
  elM.innerHTML='<option value="">Tous les mois</option>'+
    moisDispo.map(m=>`<option value="${m}">${moisLabel(m)}</option>`).join('');
  if(pM)elM.value=pM;

  // Dates par défaut pour filtres jour/semaine
  if(db.entries.length){
    const dates=db.entries.map(e=>e.date).sort();
    const minD=dates[0];const maxD=dates[dates.length-1];
    const df=document.getElementById('k-date-from');const dt=document.getElementById('k-date-to');
    if(df&&!df.value)df.value=minD;
    if(dt&&!dt.value)dt.value=maxD;
    // Semaines
    const wf=document.getElementById('k-week-from');const wt=document.getElementById('k-week-to');
    if(wf&&!wf.value)wf.value=dateToWeekInput(minD);
    if(wt&&!wt.value)wt.value=dateToWeekInput(maxD);
  }

  // Sites
  const userSites=isAdmin?[...new Set(db.entries.map(e=>e.site))].sort():getUserSites();
  const elS=document.getElementById('k-site');const pS=elS.value;
  elS.innerHTML=(isAdmin?'<option value="">Tous les sites</option>':'<option value="">Tous mes sites</option>')+
    userSites.map(s=>`<option>${s}</option>`).join('');
  if(pS&&userSites.includes(pS))elS.value=pS;
  if(!isAdmin&&userSites.length===1)elS.value=userSites[0];
}

function dateToWeekInput(dateStr){
  // Convertit 2026-05-13 → 2026-W20
  const d=new Date(dateStr);
  const wn=getWkN(d);
  return`${d.getFullYear()}-W${String(wn).padStart(2,'0')}`;
}
function weekInputToRange(wStr){
  // 2026-W20 → {from:'2026-05-11', to:'2026-05-15'}
  if(!wStr)return null;
  const [y,w]=wStr.split('-W').map(Number);
  // Lundi de la semaine ISO
  const jan4=new Date(y,0,4);
  const mon=new Date(jan4);
  mon.setDate(jan4.getDate()-((jan4.getDay()||7)-1)+(w-1)*7);
  const fri=new Date(mon);fri.setDate(mon.getDate()+6);
  const fmt=d=>`${d.getFullYear()}-${String(d.getMonth()+1).padStart(2,'0')}-${String(d.getDate()).padStart(2,'0')}`;
  return{from:fmt(mon),to:fmt(fri)};
}

function getKpiData(){
  const isAdmin=CURRENT?.role==='admin';
  const siteFilt=document.getElementById('k-site')?.value;
  const valOnly=document.getElementById('k-valonly')?.checked;
  let data=filterByProfile(db.entries);
  if(siteFilt)data=data.filter(e=>e.site===siteFilt);
  const posteFilt=document.getElementById('k-poste')?.value||'';
  if(posteFilt)data=data.filter(e=>e.act===posteFilt);
  if(valOnly)data=data.filter(e=>e.status==='validated');

  if(kpiGran==='jour'){
    const from=document.getElementById('k-date-from')?.value;
    const to=document.getElementById('k-date-to')?.value;
    if(from)data=data.filter(e=>e.date>=from);
    if(to)data=data.filter(e=>e.date<=to);
  } else if(kpiGran==='semaine'){
    const wFrom=document.getElementById('k-week-from')?.value;
    const wTo=document.getElementById('k-week-to')?.value;
    const rFrom=weekInputToRange(wFrom);const rTo=weekInputToRange(wTo);
    if(rFrom)data=data.filter(e=>e.date>=rFrom.from);
    if(rTo)data=data.filter(e=>e.date<=rTo.to);
  } else { // mois
    const year=document.getElementById('k-annee')?.value;
    const moisFilt=document.getElementById('k-mois-unique')?.value;
    if(moisFilt)data=data.filter(e=>e.date.startsWith(moisFilt));
    else if(year)data=data.filter(e=>e.date.startsWith(year));
  }
  return data;
}

function renderKpi(){
  const isAdmin=CURRENT?.role==='admin';
  // Peupler k-poste
  (function(){const el=document.getElementById('k-poste');if(el&&el.options.length<=1){const postes=[...new Set(filterByProfile(db.entries).map(e=>e.act))].filter(Boolean).sort();el.innerHTML='<option value="">Tous les postes</option>'+postes.map(p=>`<option>${p}</option>`).join('');}})();
  const data=getKpiData();

  // KPIs globaux
  const totH=data.reduce((s,e)=>s+e.h,0);
  const dwr=data.filter(e=>e.taux>0);
  const totC=dwr.reduce((s,e)=>s+coutTotalReel(e),0);
  const tauxMoy=dwr.reduce((s,e)=>s+e.h,0)>0?dwr.reduce((s,e)=>s+e.taux*e.h,0)/dwr.reduce((s,e)=>s+e.h,0):0;
  // Calculs détaillés
  const totCbrut=dwr.reduce((s,e)=>s+(e.cout||0),0);
  const totRepas=data.reduce((s,e)=>s+(e.repas||0),0);
  const totCreel=data.reduce((s,e)=>s+coutTotalReel(e),0);
  const totHn=data.reduce((s,e)=>s+(e.hn||0),0);
  const totHs25=data.reduce((s,e)=>s+(e.hs25||0),0);
  const totHs50=data.reduce((s,e)=>s+(e.hs50||0),0);
  const totTR=data.filter(e=>db.actsConfig?.[e.act]?.type==='sedentaire').reduce((s,e)=>s+(e.repas||0),0);
  const totPan=data.filter(e=>db.actsConfig?.[e.act]?.type==='roulant').reduce((s,e)=>s+(e.repas||0),0);
  const coeffAff=db.coeff||2;
  // Rangée 1
  const elCout=document.getElementById('k-cout');if(elCout)elCout.textContent=totCbrut>0?fmtE(totCbrut):'0 €';
  const elRepas=document.getElementById('k-repas');if(elRepas)elRepas.textContent=fmtE(totRepas);
  const elCoutBrut=document.getElementById('k-cout-brut');if(elCoutBrut)elCoutBrut.textContent=fmtE(totCbrut+totRepas);
  const elCoutReel=document.getElementById('k-cout-reel');if(elCoutReel)elCoutReel.textContent=fmtE(totCreel);
  // Rangée 2
  const elHn=document.getElementById('k-hn');if(elHn)elHn.textContent=fmtH(totHn);
  const elHs25=document.getElementById('k-hs25');if(elHs25)elHs25.textContent=fmtH(totHs25);
  const elHs50=document.getElementById('k-hs50');if(elHs50)elHs50.textContent=fmtH(totHs50);
  const elH=document.getElementById('k-h');if(elH)elH.textContent=fmtH(totH)||'0h';
  // Rangée 3
  const elNb=document.getElementById('k-nb');if(elNb)elNb.textContent=new Set(data.map(e=>e.nom)).size;
  const elTaux=document.getElementById('k-taux');if(elTaux)elTaux.textContent=tauxMoy>0?tauxMoy.toFixed(2)+' €/h':'—';
  const elCoeff=document.getElementById('k-coeff');if(elCoeff)elCoeff.textContent='×'+coeffAff.toFixed(1);
  const elRepDet=document.getElementById('k-repas-detail');if(elRepDet)elRepDet.textContent='TR '+fmtE(totTR)+' · Paniers '+fmtE(totPan);


  // ── Axe temporel selon granularité ───────────────────────────────────────
  let axeLabels=[], axeKeys=[], getKey;

  if(kpiGran==='jour'){
    // Jours distincts présents dans les données
    const dates=[...new Set(data.map(e=>e.date))].sort();
    axeLabels=dates.map(d=>d.split('-').reverse().join('/'));
    axeKeys=dates;
    getKey=e=>e.date;
  } else if(kpiGran==='semaine'){
    // Semaines distinctes
    const weeks=[...new Set(data.map(e=>e.wk))].sort();
    axeLabels=weeks.map(w=>{
      const wn=getWkN(new Date(w));
      const d=new Date(w);
      return`S${wn} ${fmtD(d)}`;
    });
    axeKeys=weeks;
    getKey=e=>e.wk;
  } else {
    // Mois selon l'année/filtre sélectionné
    const year=document.getElementById('k-annee')?.value;
    const moisFilt=document.getElementById('k-mois-unique')?.value;
    if(moisFilt){
      // Un seul mois → barres par semaine dans ce mois
      const weeks=[...new Set(data.map(e=>e.wk))].sort();
      axeLabels=weeks.map(w=>{const wn=getWkN(new Date(w));return`S${wn}`;});
      axeKeys=weeks;getKey=e=>e.wk;
    } else {
      // Tous les mois de l'année
      axeKeys=MOIS_FR.map((_,i)=>`${year}-${String(i+1).padStart(2,'0')}`);
      axeLabels=MOIS_FR;
      getKey=e=>e.date.slice(0,7);
    }
  }

  // Agrégation par axe
  const byAxe={};
  axeKeys.forEach(k=>{byAxe[k]={h:0,cout:0};});
  data.forEach(e=>{const k=getKey(e);if(byAxe[k]!==undefined){byAxe[k].h+=e.h;byAxe[k].cout+=coutTotalReel(e);}});
  const maxAxe=Math.max(...Object.values(byAxe).map(v=>v.cout),1);

  document.getElementById('k-by-month').innerHTML=
    axeKeys.some(k=>byAxe[k]?.cout>0)
    ?axeKeys.map((k,i)=>{const v=byAxe[k];return`<div class="kpi-bar-row">
      <span class="kpi-bar-lbl" style="width:${kpiGran==='jour'?'80':'100'}px">${axeLabels[i]}</span>
      <div class="kpi-bar-track"><div class="kpi-bar-fill" style="width:${v.cout>0?Math.max(Math.round(v.cout/maxAxe*100),2):0}%;background:${v.cout>0?'var(--red)':'transparent'}">
        ${v.cout>0?`<span>${fmtE(v.cout)}</span>`:''}
      </div></div>
      <span class="kpi-bar-val" style="color:${v.cout>0?'var(--text)':'#CCC'}">${v.cout>0?fmtH(v.h):'—'}</span>
    </div>`;}).join('')
    :'<p class="empty">Aucune donnée pour cette période.</p>';

  // ── Section admin : bilan par site ──────────────────────────────────────
  if(isAdmin){
    const sites=[...new Set(data.map(e=>e.site))].sort();
    const bySM={};sites.forEach(s=>{bySM[s]={};axeKeys.forEach(k=>{bySM[s][k]={h:0,cout:0};});});
    data.forEach(e=>{const s=e.site;const k=getKey(e);if(bySM[s]&&bySM[s][k]!==undefined){bySM[s][k].cout+=coutTotalReel(e);bySM[s][k].h+=e.h;}});
    let smHtml='';
    sites.forEach((site,si)=>{
      const color=SITE_COLORS[si%SITE_COLORS.length];
      const siteTot=Object.values(bySM[site]).reduce((s,v)=>s+v.cout,0);
      const siteH=Object.values(bySM[site]).reduce((s,v)=>s+v.h,0);
      const maxS=Math.max(...Object.values(bySM[site]).map(v=>v.cout),1);
      smHtml+=`<div style="margin-bottom:14px;padding-bottom:12px;border-bottom:1px solid #EBEBEB">
        <div style="display:flex;align-items:center;justify-content:space-between;margin-bottom:8px">
          <div style="display:flex;align-items:center;gap:8px"><div style="width:10px;height:10px;border-radius:50%;background:${color}"></div><span style="font-size:13px;font-weight:700">${site}</span></div>
          <div><span style="font-size:14px;font-weight:800;color:var(--blue)">${fmtE(siteTot)}</span><span style="font-size:11px;color:var(--muted);margin-left:8px">${fmtH(siteH)}</span></div>
        </div>`+
        axeKeys.map((k,i)=>{const v=bySM[site][k];return`<div class="kpi-bar-row" style="margin-bottom:3px">
          <span class="kpi-bar-lbl" style="width:${kpiGran==='jour'?'68':'44'}px;font-size:10px">${axeLabels[i]}</span>
          <div class="kpi-bar-track" style="height:16px"><div class="kpi-bar-fill" style="width:${v.cout>0?Math.max(Math.round(v.cout/maxS*100),2):0}%;background:${color}">
            ${v.cout>0?`<span style="font-size:10px">${fmtE(v.cout)}</span>`:''}
          </div></div>
          <span class="kpi-bar-val" style="font-size:10px;width:70px;color:${v.cout>0?'var(--text)':'#CCC'}">${v.cout>0?fmtH(v.h):'—'}</span>
        </div>`;}).join('')+'</div>';
    });
    document.getElementById('k-site-month').innerHTML=smHtml||'<p class="empty">Aucune donnée.</p>';

    // Tableau croisé axe × site
    const activeAxe=axeKeys.filter(k=>Object.values(bySM).some(s=>s[k]?.cout>0));
    const bySite2={};sites.forEach(s=>{bySite2[s]={};axeKeys.forEach(k=>{bySite2[s][k]=0;});});
    data.forEach(e=>{const s=e.site;const k=getKey(e);if(bySite2[s]&&bySite2[s][k]!==undefined)bySite2[s][k]+=coutTotalReel(e);});
    if(sites.length&&activeAxe.length){
      const allVals=sites.flatMap(s=>activeAxe.map(k=>bySite2[s][k]));
      const maxVal=Math.max(...allVals,1);const threshold=maxVal*0.6;
      const byAxeTot={};activeAxe.forEach(k=>{byAxeTot[k]=sites.reduce((s,site)=>s+(bySite2[site][k]||0),0);});
      let html=`<table class="cross-table"><thead><tr><th>Site ↓ / ${kpiGran==='jour'?'Jour':''}${kpiGran==='semaine'?'Semaine':''}${kpiGran==='mois'?'Mois':''} →</th>`;
      activeAxe.forEach((k,i)=>{html+=`<th>${axeLabels[axeKeys.indexOf(k)]||k}</th>`;});
      html+=`<th style="background:#1A2A3A">Total</th></tr></thead><tbody>`;
      sites.forEach((site,si)=>{
        const color=SITE_COLORS[si%SITE_COLORS.length];
        const rowTot=activeAxe.reduce((s,k)=>s+(bySite2[site][k]||0),0);
        html+=`<tr><td><span style="display:inline-block;width:8px;height:8px;border-radius:50%;background:${color};margin-right:5px"></span>${site}</td>`;
        activeAxe.forEach(k=>{const v=bySite2[site][k]||0;html+=`<td class="${v===0?'cell-0':v>=threshold?'cell-hi':''}">${v>0?fmtE(v):'—'}</td>`;});
        html+=`<td style="font-weight:800;color:var(--blue);background:#EFF6FF">${fmtE(rowTot)}</td></tr>`;
      });
      html+=`<tr class="cross-total-row"><td>TOTAL</td>`;
      activeAxe.forEach(k=>{html+=`<td>${fmtE(byAxeTot[k])}</td>`;});
      html+=`<td>${fmtE(totC)}</td></tr></tbody></table>`;
      document.getElementById('k-cross').innerHTML=html;
    } else document.getElementById('k-cross').innerHTML='<p class="empty">Données insuffisantes.</p>';
  }

  // Par agence d'intérim
  const byAg={};data.forEach(e=>{if(!byAg[e.agence])byAg[e.agence]={h:0,cout:0};byAg[e.agence].h+=e.h;byAg[e.agence].cout+=coutTotalReel(e);});
  const agS=Object.entries(byAg).sort((a,b)=>b[1].cout-a[1].cout);const maxAg=Math.max(...agS.map(([,v])=>v.cout),1);
  document.getElementById('k-by-ag').innerHTML=agS.length?agS.map(([ag,v],i)=>`<div class="kpi-bar-row"><span class="kpi-bar-lbl"><span class="badge b-ag" style="font-size:9px">${ag}</span></span><div class="kpi-bar-track"><div class="kpi-bar-fill" style="width:${Math.max(Math.round(v.cout/maxAg*100),2)}%;background:${SITE_COLORS[i%SITE_COLORS.length]}"><span>${fmtE(v.cout)}</span></div></div><span class="kpi-bar-val">${fmtH(v.h)}</span></div>`).join(''):'<p class="empty">Aucune donnée.</p>';

  // Top intérimaires
  const byN={};data.forEach(e=>{if(!byN[e.nom])byN[e.nom]={h:0,cout:0};byN[e.nom].h+=e.h;byN[e.nom].cout+=coutTotalReel(e);});
  const topN=Object.entries(byN).sort((a,b)=>b[1].cout-a[1].cout).slice(0,10);const maxN=topN.length?Math.max(...topN.map(([,v])=>v.cout),1):1;
  document.getElementById('k-top').innerHTML=topN.length?topN.map(([nom,v])=>`<div class="kpi-bar-row"><span class="kpi-bar-lbl" style="font-size:11px" title="${nom}">${nom.split(' ')[0]}</span><div class="kpi-bar-track"><div class="kpi-bar-fill" style="width:${Math.max(Math.round(v.cout/maxN*100),2)}%;background:var(--navy)"><span>${fmtE(v.cout)}</span></div></div><span class="kpi-bar-val">${fmtH(v.h)}</span></div>`).join(''):'<p class="empty">Aucune donnée.</p>';
}

function renderList(){
  syncSiteFilters(['l-site']);
  const mois=document.getElementById('l-mois').value,fs=document.getElementById('l-site').value,fa=document.getElementById('l-act').value,fn=document.getElementById('l-nom').value,fag=document.getElementById('l-ag').value,fst=document.getElementById('l-stat').value;
  const base=filterByProfile(db.entries);
  const acts=[...new Set(base.map(e=>e.act))].sort();const noms=[...new Set(base.map(e=>e.nom))].sort();const ags=[...new Set(base.map(e=>e.agence))].sort();
  document.getElementById('l-act').innerHTML='<option value="">Tous postes</option>'+acts.map(s=>`<option${s===fa?' selected':''}>${s}</option>`).join('');
  document.getElementById('l-nom').innerHTML='<option value="">Tous intérimaires</option>'+noms.map(s=>`<option${s===fn?' selected':''}>${s}</option>`).join('');
  document.getElementById('l-ag').innerHTML='<option value="">Toutes agences</option>'+ags.map(s=>`<option${s===fag?' selected':''}>${s}</option>`).join('');
  let data=base;if(mois)data=data.filter(e=>e.date.startsWith(mois));if(fs)data=data.filter(e=>e.site===fs);if(fa)data=data.filter(e=>e.act===fa);if(fn)data=data.filter(e=>e.nom===fn);if(fag)data=data.filter(e=>e.agence===fag);if(fst)data=data.filter(e=>e.status===fst);
  data=[...data].sort((a,b)=>(b.wk||b.date).localeCompare(a.wk||a.date));
  const cont=document.getElementById('list-table');if(!data.length){cont.innerHTML='<p class="empty">Aucune entrée.</p>';return;}
  const totH=data.reduce((s,e)=>s+e.h,0);const totC=data.filter(e=>e.taux>0).reduce((s,e)=>s+(e.cout||0),0);
  cont.innerHTML=`<div class="dtable-wrap" style="overflow-x:auto"><table style="min-width:900px"><thead><tr>
    <th style="width:90px;min-width:90px">Date</th>
    <th style="min-width:130px">Intérimaire</th>
    <th style="width:90px;min-width:90px">Agence int.</th>
    <th style="width:90px;min-width:90px">Site</th>
    <th style="width:120px;min-width:110px">Poste</th>
    <th style="width:90px;min-width:90px">Plage</th>
    <th style="width:54px;min-width:54px">Pause</th>
    <th style="width:64px;min-width:60px">H. nettes</th>
    <th style="width:54px;min-width:54px">Taux</th>
    <th style="width:80px;min-width:76px">Coût</th>
    <th style="width:80px;min-width:78px">Statut</th>
    <th style="width:28px;min-width:28px"></th>
  </tr></thead><tbody>${data.map(e=>`<tr>
    <td>${(e.wk||e.date).split('-').reverse().join('/')}</td>
    <td style="font-weight:600">${e.nom}</td>
    <td><span class="badge b-ag">${e.agence}</span></td>
    <td><span class="badge b-site">${e.site}</span></td>
    <td><span class="badge b-act">${e.act}</span></td>
    <td style="font-size:11px;color:var(--muted)">${e.deb}–${e.fin}</td>
    <td style="font-size:11px;color:var(--amber);text-align:center">${e.pause||0} min</td>
    <td style="font-weight:700;text-align:center">${fmtH(e.h)}</td>
    <td style="font-size:11px;color:var(--muted);text-align:center">${e.taux?e.taux.toFixed(2)+' €':''}</td>
    <td style="font-weight:700;color:var(--blue);text-align:right">${e.cout?fmtE(e.cout):''}</td>
    <td>${statusBadge(e.status||'pending')}</td>
    <td><button class="btn-del" onclick="delEntry(${e.id})">×</button></td>
  </tr>`).join('')}</tbody><tfoot><tr>
    <td colspan="7" style="font-size:10px;color:var(--muted);padding-top:8px">${data.length} ligne(s)</td>
    <td style="font-weight:700;padding-top:8px;text-align:center">${fmtH(totH)}</td>
    <td></td>
    <td style="font-weight:700;color:var(--blue);padding-top:8px;text-align:right">${fmtE(totC)}</td>
    <td></td>
  </tr></tfoot></table></div>`;
}
function delEntry(id){if(!confirm('Supprimer ?'))return;db.entries=db.entries.filter(e=>e.id!==id);save();updatePendingBadge();renderList();}

