// DÉCLARATIF
// ══════════════════════════════════════════════════════════════════════════════
function renderDecl(){
  syncSiteFilters(['d-site']);
  const mois=document.getElementById('d-mois').value,site=document.getElementById('d-site').value,valOnly=document.getElementById('d-valonly').checked,showCout=document.getElementById('d-showcout').checked;
  let data=filterByProfile(db.entries).filter(e=>(!mois||e.date.startsWith(mois))&&(!site||e.site===site));
  if(valOnly)data=data.filter(e=>e.status==='validated');
  if(!data.length){document.getElementById('decl-content').innerHTML='<p class="empty">Aucune donnée.</p>';return;}
  const sitesInData=[...new Set(data.map(e=>e.site))].sort();
  document.getElementById('decl-content').innerHTML=sitesInData.map(s=>{const sData=data.filter(e=>e.site===s).sort((a,b)=>a.date.localeCompare(b.date));const byWeek={};sData.forEach(e=>{if(!byWeek[e.wk])byWeek[e.wk]=[];byWeek[e.wk].push(e);});const totH=sData.reduce((a,e)=>a+e.h,0);const totC=sData.filter(e=>e.taux>0).reduce((a,e)=>a+(e.cout||0),0);return`<div class="scard"><div style="display:flex;justify-content:space-between;margin-bottom:12px;padding-bottom:10px;border-bottom:2px solid var(--red)"><div><span style="font-size:15px;font-weight:800">${s}</span><span style="margin-left:10px;font-size:11px;color:var(--muted)">${moisLabel(mois)}</span></div><div style="text-align:right"><div style="font-weight:700">${fmtH(totH)} nettes</div>${showCout?`<div style="font-weight:700;color:var(--blue)">${fmtE(totC)}</div>`:''}</div></div>${Object.entries(byWeek).sort((a,b)=>a[0].localeCompare(b[0])).map(([wk,wData])=>{const ws=db.weekValidations[s+'|'+wk]||{status:'pending'};const wH=wData.reduce((a,e)=>a+e.h,0);const wC=wData.filter(e=>e.taux>0).reduce((a,e)=>a+(e.cout||0),0);return`<div style="margin-bottom:12px"><div style="display:flex;justify-content:space-between;align-items:center;margin-bottom:7px"><div style="display:flex;gap:6px;align-items:center"><span class="badge b-week">${weekKeyLabel(wk)}</span>${statusBadge(ws.status)}</div><div style="font-size:11px;font-weight:700">${fmtH(wH)} nettes${showCout?' · <span style="color:var(--blue)">'+fmtE(wC)+'</span>':''}</div></div><table style="font-size:11px;width:100%;min-width:600px"><thead><tr><th style="width:90px;min-width:90px">Date</th><th style="min-width:120px">Intérimaire</th><th style="width:80px;min-width:80px">Agence</th><th style="min-width:100px">Poste</th><th style="width:90px;min-width:90px">Plage</th><th style="width:58px;min-width:58px">Pause</th><th style="width:64px;min-width:60px">H. nettes</th>${showCout?'<th style="width:54px;min-width:54px">Taux</th><th style="width:76px;min-width:72px">Coût</th>':''}</tr></thead><tbody>${wData.map(e=>`<tr><td>${(e.wk||e.date).split('-').reverse().join('/')}</td><td style="font-weight:600">${e.nom}</td><td><span class="badge b-ag" style="font-size:9px">${e.agence}</span></td><td>${e.act}</td><td style="color:var(--muted)">${e.deb}–${e.fin}</td><td style="color:var(--amber);text-align:center">${e.pause||0} min</td><td style="font-weight:700;text-align:center">${fmtH(e.h)}</td>${showCout?`<td style="color:var(--muted)">${e.taux?e.taux.toFixed(2)+' €':''}</td><td style="font-weight:700;color:var(--blue);text-align:right">${e.cout?fmtE(e.cout):''}</td>`:''}</tr>`).join('')}</tbody></table></div>`;}).join('')}<div style="margin-top:10px;padding-top:8px;border-top:1px solid #EBEBEB;display:flex;justify-content:space-between;font-size:11px;color:var(--muted)"><span>Visa responsable : ${CURRENT?.label||''}</span><span>____________________</span></div></div>`;}).join('');
}
function printDecl(){const pz=document.getElementById('print-zone');pz.innerHTML=`<div style="font-family:Arial,sans-serif;padding:24px;font-size:11px;color:#000"><div style="display:flex;justify-content:space-between;margin-bottom:18px;padding-bottom:12px;border-bottom:3px solid #CC2B1B"><div><div style="font-size:18px;font-weight:800;color:#CC2B1B">DISTRITEC</div><div style="font-size:12px;font-weight:600;margin-top:3px">Relevé mensuel des heures intérimaires</div></div><div style="text-align:right;font-size:10px;color:#666">Imprimé le ${new Date().toLocaleDateString('fr-FR')}<br>${CURRENT?.label||''}</div></div>${document.getElementById('decl-content').innerHTML}</div>`;window.print();setTimeout(()=>pz.innerHTML='',1500);}

