function renderParams(){
  if(!CURRENT)return;
  const isAdmin=CURRENT.role==='admin';
  // Mon profil
  const userSites=isAdmin?['Accès total — tous les sites']:getUserSites();
  const users=loadUsers();
  document.getElementById('my-profile').innerHTML=`
    <div class="pc-header">
      <div><span class="pc-name">${CURRENT.label}</span><span class="badge ${isAdmin?'b-admin':'b-resp'}" style="margin-left:8px">${isAdmin?'Admin':'Responsable de site'}</span></div>
      <span style="font-size:11px;color:var(--muted)">Identifiant : <strong>${CURRENT.id}</strong></span>
    </div>
    <div style="font-size:11px;color:var(--muted);margin-bottom:8px">${isAdmin?'Accès complet — tous les sites et toutes les fonctionnalités':'Sites accessibles :'}</div>
    <div class="sites-secondary">${userSites.map(s=>`<span class="site-sec-tag">📍 ${s}</span>`).join('')}</div>`;

  // Section admin
  document.getElementById('admin-section').style.display=isAdmin?'':'none';
  if(!isAdmin)return;

  // Tableau des comptes
  document.getElementById('users-table').innerHTML=`<table><thead><tr>
    <th style="width:110px">Identifiant</th><th>Nom</th><th style="width:70px">Rôle</th>
    <th style="width:130px">Site principal</th><th>Sites secondaires (accès congé)</th>
    <th style="width:110px">Mot de passe</th><th style="width:30px"></th>
  </tr></thead><tbody>`+
  users.map((u,idx)=>`<tr>
    <td style="font-family:monospace;font-weight:600">${u.id}</td>
    <td>${u.label}</td>
    <td><span class="badge ${u.role==='admin'?'b-admin':'b-resp'}">${u.role==='admin'?'Admin':'Site'}</span></td>
    <td>${u.sites?u.sites.join(', '):'—'}</td>
    <td>
      ${u.role==='site'?`<div style="display:flex;align-items:center;gap:6px;flex-wrap:wrap">
        ${(u.sitesExtra||[]).map(s=>`<span class="site-sec-tag" style="font-size:10px">${s}<button class="site-sec-del" onclick="removeSiteExtra(${idx},'${s}')">×</button></span>`).join('')}
        <select style="height:24px;font-size:10px;border:1px dashed var(--border);border-radius:4px;padding:0 6px;background:white;color:var(--blue)" onchange="addSiteExtra(${idx},this)">
          <option value="">+ Ajouter site…</option>
          ${db.sites.filter(s=>!(u.sites||[]).includes(s)&&!(u.sitesExtra||[]).includes(s)).map(s=>`<option>${s}</option>`).join('')}
        </select>
      </div>`:'<span style="font-size:11px;color:var(--muted)">N/A</span>'}
    </td>
    <td><input type="password" value="${u.pwd}" id="upwd-${idx}" style="height:24px;font-size:10px;width:90px;border:1px solid var(--border);border-radius:4px;padding:0 6px" onchange="updateUserPwd(${idx},this.value)"/>
    <button class="btn-del" onclick="togglePwd(${idx})" style="font-size:11px">👁</button></td>
    <td></td>
  </tr>`).join('')+'</tbody></table>';

  // Listes
  document.getElementById('cfg-sites').innerHTML=db.sites.map(s=>`<span class="tag">${s}<button class="tag-del" onclick="delSite('${s}')">×</button></span>`).join('');
  document.getElementById('cfg-ags').innerHTML=db.agences.map(a=>`<span class="tag">${a}<button class="tag-del" onclick="delAgence('${a}')">×</button></span>`).join('');
  document.getElementById('cfg-acts').innerHTML=db.acts.map(a=>`<span class="tag">${a}<button class="tag-del" onclick="delAct('${a}')">×</button></span>`).join('');
  // Paramètres financiers
  const coeff=db.coeff||2;
  const pf=document.getElementById('params-financiers');
  if(pf)pf.innerHTML=`
    <div style="display:flex;align-items:center;gap:14px;flex-wrap:wrap">
      <div class="fg" style="min-width:100px">
        <label class="lbl">Coefficient global ×</label>
        <input type="text" id="cfg-coeff" value="${coeff}" style="height:34px;font-size:15px;font-weight:700;text-align:center"/>
      </div>
      <button class="btn-sm" style="align-self:flex-end" onclick="saveFinancial()">Enregistrer</button>
      <span style="font-size:11px;color:var(--muted);align-self:flex-end">Coût réel = Coût brut ×${coeff} (si pas de coeff par agence)</span>
    </div>`;
  // Coefficients par agence
  renderCoeffParPoste();
  renderTauxMensuels();
  syncExpFilters();
}

function addSiteExtra(idx,sel){
  const site=sel.value;if(!site)return;
  const users=loadUsers();if(!users[idx].sitesExtra)users[idx].sitesExtra=[];
  if(!users[idx].sitesExtra.includes(site))users[idx].sitesExtra.push(site);
  saveUsers(users);sel.value='';
  // Mettre à jour l'utilisateur courant si c'est lui
  if(CURRENT&&CURRENT.id===users[idx].id)CURRENT.sitesExtra=[...users[idx].sitesExtra];
  renderParams();populateSiteAct();updatePendingBadge();
}
function removeSiteExtra(idx,site){
  const users=loadUsers();if(!users[idx].sitesExtra)return;
  users[idx].sitesExtra=users[idx].sitesExtra.filter(s=>s!==site);saveUsers(users);
  if(CURRENT&&CURRENT.id===users[idx].id)CURRENT.sitesExtra=[...users[idx].sitesExtra];
  renderParams();populateSiteAct();
}
function updateUserPwd(idx,val){if(!val||val.length<4){alert('Min 4 caractères.');return;}const users=loadUsers();users[idx].pwd=val;saveUsers(users);alert('Mot de passe mis à jour pour '+users[idx].label+'.');}
function togglePwd(idx){const el=document.getElementById('upwd-'+idx);if(el)el.type=el.type==='password'?'text':'password';}
function changePwd(){
  const p1=document.getElementById('new-pwd1').value;const p2=document.getElementById('new-pwd2').value;
  const el=document.getElementById('pwd-alert');
  if(!p1||p1.length<4){el.className='alert alert-err';el.textContent='Minimum 4 caractères.';el.style.display='block';return;}
  if(p1!==p2){el.className='alert alert-err';el.textContent='Les mots de passe ne correspondent pas.';el.style.display='block';return;}
  const users=loadUsers();const idx=users.findIndex(u=>u.id===CURRENT.id);if(idx<0)return;
  users[idx].pwd=p1;saveUsers(users);CURRENT.pwd=p1;
  el.className='alert alert-ok';el.textContent='Mot de passe modifié.';el.style.display='block';
  document.getElementById('new-pwd1').value='';document.getElementById('new-pwd2').value='';
  setTimeout(()=>el.style.display='none',3000);
}
function addSite(){const v=document.getElementById('cfg-site-inp').value.trim();if(!v||db.sites.includes(v))return;db.sites.push(v);save();populateSiteAct();renderParams();document.getElementById('cfg-site-inp').value='';}
function delSite(s){if(!confirm(`Supprimer "${s}" ?`))return;db.sites=db.sites.filter(x=>x!==s);save();populateSiteAct();renderParams();}
function addAgence(){const v=document.getElementById('cfg-ag-inp').value.trim();if(!v||db.agences.includes(v))return;db.agences.push(v);save();populateAgenceSelect();renderParams();document.getElementById('cfg-ag-inp').value='';}
function delAgence(a){if(!confirm(`Supprimer "${a}" ?`))return;db.agences=db.agences.filter(x=>x!==a);save();populateAgenceSelect();renderParams();}
function addAct(){const v=document.getElementById('cfg-act-inp').value.trim();if(!v||db.acts.includes(v))return;db.acts.push(v);save();populateSiteAct();renderParams();document.getElementById('cfg-act-inp').value='';}
function delAct(a){if(!confirm(`Supprimer "${a}" ?`))return;db.acts=db.acts.filter(x=>x!==a);save();populateSiteAct();renderParams();}
function clearAll(){if(!confirm('Effacer toutes les données ? Irréversible.'))return;db.entries=[];db.memo={};db.weekValidations={};save();updatePendingBadge();calRows=[];calState={};render();}

