function syncExpFilters(){
  const mois=getMoisList();const sites=[...new Set(db.entries.map(e=>e.site))].sort();
  const el1=document.getElementById('exp-mois');if(el1)el1.innerHTML='<option value="">Toutes périodes</option>'+mois.map(m=>`<option value="${m}">${moisLabel(m)}</option>`).join('');
  const el2=document.getElementById('exp-site');if(el2)el2.innerHTML='<option value="">Tous les sites</option>'+sites.map(s=>`<option>${s}</option>`).join('');
}
function exportExcel(){
  if(CURRENT?.role!=='admin'){alert('Export réservé à l\'admin.');return;}
  const mois=document.getElementById('exp-mois').value;const site=document.getElementById('exp-site').value;const valOnly=document.getElementById('exp-valonly').checked;
  const stL={'pending':'En attente','validated':'Validée','rejected':'Refusée'};
  const R='CC2B1B',N='3D3A3A',LG='E6F5ED',LR='FEE2E2';
  let data=db.entries;if(mois)data=data.filter(e=>e.date.startsWith(mois));if(site)data=data.filter(e=>e.site===site);if(valOnly)data=data.filter(e=>e.status==='validated');
  data=[...data].sort((a,b)=>a.site.localeCompare(b.site)||a.date.localeCompare(b.date));
  const wb=XLSX.utils.book_new();
  const S=(v,bg=N)=>({v,s:{fill:{fgColor:{rgb:bg}},font:{bold:true,color:{rgb:'FFFFFF'},name:'Arial',sz:10},alignment:{horizontal:'center',vertical:'center',wrapText:true},border:{top:{style:'thin',color:{rgb:'DDDDDD'}},bottom:{style:'thin',color:{rgb:'DDDDDD'}},left:{style:'thin',color:{rgb:'DDDDDD'}},right:{style:'thin',color:{rgb:'DDDDDD'}}}}});
  const C=(v,bg,bold=false,c='2A2A2A',fmt)=>({v,t:typeof v==='number'?'n':'s',s:{fill:bg?{fgColor:{rgb:bg}}:{},font:{bold,color:{rgb:c},name:'Arial',sz:10},alignment:{horizontal:typeof v==='number'?'center':'left',vertical:'center'},border:{top:{style:'thin',color:{rgb:'EEEEEE'}},bottom:{style:'thin',color:{rgb:'EEEEEE'}},left:{style:'thin',color:{rgb:'EEEEEE'}},right:{style:'thin',color:{rgb:'EEEEEE'}}}},z:fmt});
  // Onglet Heures
  const aoa1=[[S('DISTRITEC — Relevé des heures intérimaires',R),...Array(12).fill({v:'',s:{}})],['Date','Semaine','Intérimaire','Agence int.','Site','Poste','Début','Fin','Pause (min)','H. nettes','Taux (€/h)','Coût (€)','Statut'].map(h=>S(h)),...data.map(e=>{const bg=e.status==='validated'?LG:e.status==='rejected'?LR:null;return[C(e.date,bg),C(weekKeyLabel(e.wk),bg),C(e.nom,bg,true),C(e.agence,bg),C(e.site,bg),C(e.act,bg),C(e.deb,bg),C(e.fin,bg),C(e.pause||0,bg),C(e.h,bg,false,'2A2A2A','0.00'),C(e.taux||0,bg,false,'2A2A2A','0.00'),C(e.cout||0,bg,false,R,'#,##0.00 €'),C(stL[e.status||'pending'],bg)];}),];
  const ws1=XLSX.utils.aoa_to_sheet(aoa1);ws1['!merges']=[{s:{r:0,c:0},e:{r:0,c:12}}];ws1['!cols']=[{wch:12},{wch:22},{wch:20},{wch:14},{wch:16},{wch:22},{wch:8},{wch:8},{wch:10},{wch:11},{wch:11},{wch:13},{wch:14}];
  XLSX.utils.book_append_sheet(wb,ws1,'Heures');
  // Onglet Bilan mensuel par site
  const sites=[...new Set(data.map(e=>e.site))].sort();const bySM={};sites.forEach(s=>{bySM[s]=Array(12).fill(0);});data.forEach(e=>{const s=e.site;const m=parseInt(e.date.slice(5,7))-1;if(bySM[s])bySM[s][m]+=(e.cout||0);});
  const byMH=Array(12).fill(0);data.forEach(e=>{byMH[parseInt(e.date.slice(5,7))-1]+=(e.cout||0);});
  const hdr2=['Site',...MOIS_FULL,'Total'];
  const aoa2=[[S('DISTRITEC — Bilan mensuel par site (€)',R),...Array(hdr2.length-1).fill({v:'',s:{}})],hdr2.map(h=>S(h)),...sites.map(s=>[C(s,null,true),...bySM[s].map(v=>C(v||0,null,false,v>0?'2A2A2A':'CCCCCC','#,##0.00 €')),C(bySM[s].reduce((a,v)=>a+v,0),null,true,R,'#,##0.00 €')]),[S('TOTAL',N),...byMH.map(v=>({...C(v,null,true,'FFFFFF','#,##0.00 €'),s:{...C(v,null,true,'FFFFFF','#,##0.00 €').s,fill:{fgColor:{rgb:'2A2727'}},font:{bold:true,color:{rgb:'FFFFFF'},name:'Arial',sz:10}}})),C(byMH.reduce((a,v)=>a+v,0),null,true,R,'#,##0.00 €')]];
  const ws2=XLSX.utils.aoa_to_sheet(aoa2);ws2['!merges']=[{s:{r:0,c:0},e:{r:0,c:hdr2.length-1}}];ws2['!cols']=[{wch:18},...Array(13).fill({wch:12})];
  XLSX.utils.book_append_sheet(wb,ws2,'Bilan mensuel par site');
  // Onglet KPIs
  const year=mois?mois.slice(0,4):new Date().getFullYear().toString();
  const byMG=Array.from({length:12},()=>({h:0,cout:0,int:new Set()}));
  data.filter(e=>e.date.startsWith(year)).forEach(e=>{const m=parseInt(e.date.slice(5,7))-1;byMG[m].h+=e.h;byMG[m].cout+=(e.cout||0);byMG[m].int.add(e.nom);});
  const aoa3=[[S(`DISTRITEC — KPIs ${year}`,R),...Array(4).fill({v:'',s:{}})],['Mois','H. nettes','Coût (€)','Nb entrées','Nb intérimaires'].map(h=>S(h)),...byMG.map((m,i)=>[C(MOIS_FULL[i]),C(m.h,null,false,'2A2A2A','0.00'),C(m.cout,null,m.cout>0,m.cout>0?R:'CCCCCC','#,##0.00 €'),C(data.filter(e=>e.date.startsWith(year)&&parseInt(e.date.slice(5,7))-1===i).length),C(m.int.size)])];
  const ws3=XLSX.utils.aoa_to_sheet(aoa3);ws3['!merges']=[{s:{r:0,c:0},e:{r:0,c:4}}];ws3['!cols']=[{wch:14},{wch:12},{wch:14},{wch:12},{wch:16}];
  XLSX.utils.book_append_sheet(wb,ws3,'KPIs annuels');
  XLSX.writeFile(wb,`distritec_heures${mois?'_'+mois:''}${site?'_'+site:''}.xlsx`);
}

// ══ HELPERS FINANCIERS ══════════════════════════════════════════════════════
function getCoeffEntry(e){
  if(db.coeffAgences&&db.coeffAgences[e.agence]!=null)return db.coeffAgences[e.agence];
  return db.coeff||2;
}
function coutReel(e){
  const cr=e.cout_reel!=null?e.cout_reel:(e.cout||0)*getCoeffEntry(e);
  return parseFloat((cr+(e.repas||0)).toFixed(2));
}
function coutTotalReel(e){
  if(e.cout_reel!=null) return parseFloat(e.cout_reel.toFixed(2));
  const coeff=getCoeffForEntry(e);
  const cr=(e.cout||0)*coeff;
  return parseFloat((cr+(e.repas||0)).toFixed(2));
}
function getRepasJour(act,h){
  if((h||0)<=4)return 0;
  const cfg=db.actsConfig?.[act];if(!cfg)return 0;
  if(cfg.repas>0)return cfg.repas;
  if(cfg.type==='roulant')return db.panierRepas||15.20;
  return db.tauxTR||9.50;
}

// ══ ONGLET ÉVOLUTION ETP ════════════════════════════════════════════════════
function initEvoFilters(){
  const data=filterByProfile(db.entries);
  const years=[...new Set(data.map(e=>e.date.slice(0,4)))].sort((a,b)=>b-a);
  const sites=[...new Set(data.map(e=>e.site))].sort();
  const agences=[...new Set(data.map(e=>e.agence))].sort();
  const postes=[...new Set(data.map(e=>e.act))].filter(Boolean).sort();
  const set=(id,opts,label)=>{
    const el=document.getElementById(id);if(!el)return;
    const cur=el.value;
    el.innerHTML=`<option value="">${label}</option>`+opts.map(o=>`<option>${o}</option>`).join('');
    if(cur)el.value=cur;
  };
  set('evo-annee',years,'Toutes');
  set('evo-site',sites,'Tous les sites');
  set('evo-agence',agences,'Toutes');
  set('evo-poste',postes,'Tous');
}

function renderEvolution(){
  initEvoFilters();
  const annee=document.getElementById('evo-annee')?.value||'';
  const site=document.getElementById('evo-site')?.value||'';
  const agence=document.getElementById('evo-agence')?.value||'';
  const poste=document.getElementById('evo-poste')?.value||'';
  const base=parseFloat(document.getElementById('evo-base')?.value)||151.67;
  const posteFilter=document.getElementById('evo-poste-filter')?.value||'';

  // dataGlobal = sans filtre agence (graphique cumul)
  let dataGlobal=filterByProfile(db.entries);
  if(annee)dataGlobal=dataGlobal.filter(e=>e.date.startsWith(annee));
  if(site)dataGlobal=dataGlobal.filter(e=>e.site===site);
  if(poste)dataGlobal=dataGlobal.filter(e=>e.act===poste);
  // data = tous filtres y compris agence
  let data=[...dataGlobal];
  if(agence)data=data.filter(e=>e.agence===agence);

  const elChartGlobal=document.getElementById('evo-chart-global');
  const elByPoste=document.getElementById('evo-by-poste');
  const elTable=document.getElementById('evo-table');

  const moisGlobal=[...new Set(dataGlobal.map(e=>e.date.slice(0,7)))].sort();
  const mois=[...new Set(data.map(e=>e.date.slice(0,7)))].sort();
  const n=moisGlobal.length;

  if(!moisGlobal.length){
    if(elChartGlobal)elChartGlobal.innerHTML='<p class="empty">Aucune donnée.</p>';
    if(elByPoste)elByPoste.innerHTML='';
    if(elTable)elTable.innerHTML='';
    return;
  }

  // Peupler filtre poste vignettes
  (function(){
    const postes=[...new Set(data.map(e=>e.act))].filter(Boolean).sort();
    const el=document.getElementById('evo-poste-filter');
    if(el){const c=el.value;el.innerHTML='<option value="">Tous les postes</option>'+postes.map(p=>`<option>${p}</option>`).join('');if(c)el.value=c;}
  })();

  const COLORS=['#CC2B1B','#2563EB','#1A7A4A','#D97706','#7C3AED','#0891B2','#BE185D','#F59E0B'];

  // ETP global par mois
  const etpM={};moisGlobal.forEach(m=>{etpM[m]=0;});
  dataGlobal.forEach(e=>{const m=e.date.slice(0,7);if(etpM[m]!==undefined)etpM[m]+=e.h/base;});
  const vals=moisGlobal.map(m=>etpM[m]);
  const mMax=moisGlobal[vals.indexOf(Math.max(...vals))];
  const mMin=moisGlobal[vals.indexOf(Math.min(...vals))];

  // ── Graphique 1 : Cumul global ────────────────────────────────────────────
  if(elChartGlobal){
    const W=800,H=180,PL=55,PR=20,PT=16,PB=30;
    const gW=W-PL-PR,gH=H-PT-PB;
    const cx=i=>PL+i*(gW/Math.max(n-1,1));
    const maxVG=Math.max(...vals,0.1);
    const cy=v=>PT+gH-(v/maxVG*gH);
    let svg=`<svg viewBox="0 0 ${W} ${H}" xmlns="http://www.w3.org/2000/svg" style="width:100%;display:block">`;
    for(let i=0;i<=4;i++){
      const y=PT+gH*i/4;
      svg+=`<line x1="${PL}" y1="${y}" x2="${W-PR}" y2="${y}" stroke="#EBEBEB" stroke-width="1"/>`;
      svg+=`<text x="${PL-6}" y="${y+4}" text-anchor="end" font-size="10" fill="#999">${(maxVG*(1-i/4)).toFixed(1)}</text>`;
    }
    moisGlobal.forEach((m,i)=>{
      svg+=`<text x="${cx(i)}" y="${H-6}" text-anchor="middle" font-size="10" fill="#666">${moisLabel(m).slice(0,4)}</text>`;
      svg+=`<line x1="${cx(i)}" y1="${PT}" x2="${cx(i)}" y2="${PT+gH}" stroke="#F0F0EF" stroke-width="1"/>`;
    });
    svg+=`<text x="12" y="${PT+gH/2}" text-anchor="middle" font-size="10" fill="#999" transform="rotate(-90,12,${PT+gH/2})">ETP</text>`;
    let area=`M${cx(0)},${cy(etpM[moisGlobal[0]])}`;
    moisGlobal.forEach((m,i)=>{if(i>0)area+=`L${cx(i)},${cy(etpM[m])}`;});
    area+=`L${cx(n-1)},${PT+gH} L${cx(0)},${PT+gH} Z`;
    svg+=`<path d="${area}" fill="#CC2B1B" opacity="0.07"/>`;
    let path=`M${cx(0)},${cy(etpM[moisGlobal[0]])}`;
    moisGlobal.forEach((m,i)=>{if(i>0)path+=`L${cx(i)},${cy(etpM[m])}`;});
    svg+=`<path d="${path}" fill="none" stroke="#CC2B1B" stroke-width="2.5"/>`;
    moisGlobal.forEach((m,i)=>{
      const v=etpM[m],isMax=m===mMax,isMin=m===mMin;
      const col=isMax?'#CC2B1B':isMin?'#1A7A4A':'#CC2B1B';
      svg+=`<circle cx="${cx(i)}" cy="${cy(v)}" r="${isMax||isMin?5:3.5}" fill="${col}" stroke="white" stroke-width="1.5"/>`;
      svg+=`<text x="${cx(i)}" y="${cy(v)-9}" text-anchor="middle" font-size="10" font-weight="${isMax||isMin?'bold':'normal'}" fill="${col}">${v.toFixed(1)}</text>`;
    });
    svg+='</svg>';
    elChartGlobal.innerHTML=`<div style="display:flex;justify-content:space-between;font-size:11px;margin-bottom:4px">
      <span style="color:var(--muted)">Pic : <strong style="color:var(--red)">${etpM[mMax].toFixed(2)} ETP</strong> (${moisLabel(mMax)}) · Creux : <strong style="color:var(--green)">${etpM[mMin].toFixed(2)} ETP</strong> (${moisLabel(mMin)})</span>
      <span style="font-size:10px;color:#BBB;font-style:italic">Tous sites · toutes agences</span>
    </div>`+svg;
  }

  // ── Vignettes par poste ───────────────────────────────────────────────────
  if(elByPoste){
    const allPostes=[...new Set(data.map(e=>e.act))].filter(Boolean).sort();
    const postesVisible=posteFilter?allPostes.filter(p=>p===posteFilter):allPostes;
    const n2=mois.length;
    elByPoste.innerHTML=postesVisible.map((p,pi)=>{
      const color=COLORS[pi%COLORS.length];
      const W2=260,H2=120,PL2=36,PR2=10,PT2=16,PB2=24;
      const gW2=W2-PL2-PR2,gH2=H2-PT2-PB2;
      const cx2=i=>PL2+i*(gW2/Math.max(n2-1,1));
      const etpP={};mois.forEach(m=>{etpP[m]=0;});
      data.filter(e=>e.act===p).forEach(e=>{const m=e.date.slice(0,7);if(etpP[m]!==undefined)etpP[m]+=e.h/base;});
      const valsP=mois.map(m=>etpP[m]);
      const maxP=Math.max(...valsP,0.1);
      const cy2=v=>PT2+gH2-(v/maxP*gH2);
      const mMaxP=mois[valsP.indexOf(Math.max(...valsP))];
      const mMinP=mois[valsP.indexOf(Math.min(...valsP))];
      const moy=valsP.filter(v=>v>0).reduce((s,v)=>s+v,0)/(valsP.filter(v=>v>0).length||1);
      const cout=data.filter(e=>e.act===p).reduce((s,e)=>s+coutTotalReel(e),0);
      let svg2=`<svg viewBox="0 0 ${W2} ${H2}" xmlns="http://www.w3.org/2000/svg" style="width:100%;display:block">`;
      for(let i=0;i<=2;i++){
        const y=PT2+gH2*i/2;
        svg2+=`<line x1="${PL2}" y1="${y}" x2="${W2-PR2}" y2="${y}" stroke="#F0F0EF" stroke-width="1"/>`;
        svg2+=`<text x="${PL2-3}" y="${y+3}" text-anchor="end" font-size="8" fill="#CCC">${(maxP*(1-i/2)).toFixed(1)}</text>`;
      }
      mois.forEach((m,i)=>{svg2+=`<text x="${cx2(i)}" y="${H2-4}" text-anchor="middle" font-size="8" fill="#BBB">${moisLabel(m).slice(0,3)}</text>`;});
      let area2=`M${cx2(0)},${cy2(etpP[mois[0]]||0)}`;
      mois.forEach((m,i)=>{if(i>0)area2+=`L${cx2(i)},${cy2(etpP[m])}`;});
      area2+=`L${cx2(n2-1)},${PT2+gH2} L${cx2(0)},${PT2+gH2} Z`;
      svg2+=`<path d="${area2}" fill="${color}" opacity="0.1"/>`;
      let path2=`M${cx2(0)},${cy2(etpP[mois[0]]||0)}`;
      mois.forEach((m,i)=>{if(i>0)path2+=`L${cx2(i)},${cy2(etpP[m])}`;});
      svg2+=`<path d="${path2}" fill="none" stroke="${color}" stroke-width="2"/>`;
      mois.forEach((m,i)=>{
        const v=etpP[m];if(v<=0)return;
        const isMax=m===mMaxP,isMin=m===mMinP;
        const dot=isMax?'#CC2B1B':isMin?'#1A7A4A':color;
        svg2+=`<circle cx="${cx2(i)}" cy="${cy2(v)}" r="${isMax||isMin?4:2.5}" fill="${dot}" stroke="white" stroke-width="1"/>`;
        if(isMax||isMin)svg2+=`<text x="${cx2(i)}" y="${cy2(v)-6}" text-anchor="middle" font-size="8" font-weight="bold" fill="${dot}">${v.toFixed(1)}</text>`;
      });
      svg2+='</svg>';
      return`<div style="background:white;border:1.5px solid var(--border);border-radius:8px;padding:10px">
        <div style="display:flex;justify-content:space-between;align-items:flex-start;margin-bottom:4px">
          <span style="font-size:11px;font-weight:700;color:var(--navy)">${p}</span>
          <span style="font-size:10px;color:var(--muted)">moy. <strong style="color:${color}">${moy.toFixed(1)}</strong> ETP</span>
        </div>
        <div style="font-size:9px;color:var(--muted);margin-bottom:4px">Coût total : <strong style="color:var(--blue)">${fmtE(cout)}</strong></div>
        ${svg2}
      </div>`;
    }).join('');
  }

  // ── Tableau récap avec détail expandable ──────────────────────────────────
  if(elTable){
    const sitesT=[...new Set(data.map(e=>e.site))].sort();
    const postesT=[...new Set(data.map(e=>e.act))].filter(Boolean).sort();
    const agencesT=[...new Set(data.map(e=>e.agence))].filter(Boolean).sort();
    let prevEtp=null;
    let tbl=`<table style="background:white;border:1.5px solid var(--border);border-radius:8px;border-collapse:collapse;min-width:400px;width:100%">
      <thead><tr style="background:var(--navy)">
        <th style="padding:8px 6px;color:white;font-size:10px;text-align:center;width:28px"></th>
        <th style="padding:8px 12px;color:white;font-size:10px;text-align:left">Mois</th>
        <th style="padding:8px 10px;color:white;font-size:10px;text-align:center">Total ETP</th>
        <th style="padding:8px 10px;color:white;font-size:10px;text-align:center">Heures</th>
        <th style="padding:8px 10px;color:#FCA5A5;font-size:10px;text-align:right">Coût réel</th>
        <th style="padding:8px 10px;color:white;font-size:10px;text-align:center">Évol.</th>
      </tr></thead><tbody>`;
    mois.forEach(m=>{
      const mData=data.filter(e=>e.date.startsWith(m));
      const etp=mData.reduce((s,e)=>s+e.h/base,0);
      const cout=mData.reduce((s,e)=>s+coutTotalReel(e),0);
      const evo=prevEtp!=null?((etp-prevEtp)/prevEtp*100):null;
      const evoStr=evo!=null?(evo>=0?`<span style="color:var(--danger)">▲${evo.toFixed(1)}%</span>`:`<span style="color:var(--green)">▼${Math.abs(evo).toFixed(1)}%</span>`):'—';
      const isMax=m===mMax,isMin=m===mMin;
      const rowId=`trow-${m.replace('-','')}`;
      tbl+=`<tr style="border-bottom:1px solid #EEE;background:${isMax?'#FFF5F5':isMin?'#F0FFF7':''};cursor:pointer" onclick="toggleEvoDetail('${rowId}')">
        <td style="padding:6px;text-align:center"><span id="${rowId}-btn" style="display:inline-block;font-size:10px;color:var(--muted);transition:transform 0.2s;user-select:none">▶</span></td>
        <td style="padding:6px 12px;font-weight:700;font-size:11px">${moisLabel(m)}${isMax?' <span style="font-size:9px;background:var(--red);color:white;padding:1px 4px;border-radius:2px">PIC</span>':''}${isMin?' <span style="font-size:9px;background:var(--green);color:white;padding:1px 4px;border-radius:2px">CREUX</span>':''}</td>
        <td style="padding:6px 10px;text-align:center;font-weight:700;color:var(--blue)">${etp.toFixed(2)}</td>
        <td style="padding:6px 10px;text-align:center;font-size:11px;color:var(--muted)">${fmtH(etp*base)}</td>
        <td style="padding:6px 10px;text-align:right;font-size:11px;font-weight:700;color:var(--blue)">${fmtE(cout)}</td>
        <td style="padding:6px 10px;text-align:center;font-size:11px">${evoStr}</td>
      </tr>`;
      const detailByPoste=postesT.map(p=>{
        const pd=mData.filter(e=>e.act===p);if(!pd.length)return'';
        const pEtp=pd.reduce((s,e)=>s+e.h/base,0);
        const pCout=pd.reduce((s,e)=>s+coutTotalReel(e),0);
        const agDetail=agencesT.map(ag=>{
          const ad=pd.filter(e=>e.agence===ag);if(!ad.length)return'';
          const aEtp=ad.reduce((s,e)=>s+e.h/base,0);
          const aCout=ad.reduce((s,e)=>s+coutTotalReel(e),0);
          const aNb=new Set(ad.map(e=>e.nom)).size;
          return`<div style="display:flex;justify-content:space-between;padding:3px 8px 3px 16px;border-left:2px solid #DBEAFE;margin-left:8px;font-size:10px;color:var(--muted)">
            <span>${ag} <span style="background:#EFF6FF;color:var(--blue);padding:0 4px;border-radius:3px;font-size:9px">${aNb} intér.</span></span>
            <span>${aEtp.toFixed(2)} ETP · <strong style="color:var(--blue)">${fmtE(aCout)}</strong></span>
          </div>`;
        }).join('');
        return`<div style="padding:4px 0">
          <div style="display:flex;justify-content:space-between;padding:4px 8px;background:#F7F8FF;border-radius:4px;font-size:11px;font-weight:600;color:var(--navy)">
            <span>${p}</span><span>${pEtp.toFixed(2)} ETP · <strong style="color:var(--blue)">${fmtE(pCout)}</strong></span>
          </div>${agDetail}
        </div>`;
      }).join('');
      tbl+=`<tr id="${rowId}" style="display:none;background:#FAFBFF">
        <td colspan="6" style="padding:10px 16px;border-bottom:2px solid #DBEAFE">
          <div style="font-size:10px;font-weight:700;text-transform:uppercase;color:var(--muted);margin-bottom:8px">Détail ${moisLabel(m)}</div>
          ${detailByPoste||'<p style="color:var(--muted);font-size:11px">Aucune donnée.</p>'}
        </td>
      </tr>`;
      prevEtp=etp;
    });
    const totEtp=vals.reduce((s,v)=>s+v,0);
    const totCout=data.reduce((s,e)=>s+coutTotalReel(e),0);
    tbl+=`<tr style="background:#F0F0EF;border-top:2px solid var(--border);font-weight:700">
      <td></td>
      <td style="padding:7px 12px;font-size:10px;text-transform:uppercase;color:var(--muted)">Total</td>
      <td style="padding:7px 10px;text-align:center;color:var(--blue)">${totEtp.toFixed(1)}</td>
      <td style="padding:7px 10px;text-align:center;color:var(--muted)">${fmtH(totEtp*base)}</td>
      <td style="padding:7px 10px;text-align:right;color:var(--blue)">${fmtE(totCout)}</td>
      <td></td>
    </tr></tbody></table>`;
    elTable.innerHTML=tbl;
  }
}

// ══ SIMULATION CDD ══════════════════════════════════════════════════════════
function initSimFilters(){
  const data=filterByProfile(db.entries);
  const years=[...new Set(data.map(e=>e.date.slice(0,4)))].sort((a,b)=>b-a);
  const sites=[...new Set(data.map(e=>e.site))].sort();
  const postes=[...new Set(data.map(e=>e.act))].filter(Boolean).sort();
  const set=(id,opts,label)=>{
    const el=document.getElementById(id);if(!el)return;
    const cur=el.value;
    el.innerHTML=`<option value="">${label}</option>`+opts.map(o=>`<option>${o}</option>`).join('');
    if(cur)el.value=cur;
  };
  set('sim-annee',years,'Toutes');
  set('sim-site',sites,'Tous les sites');
  // sim-poste supprimé
}

function renderSimulation(){
  initSimFilters();
  const salaire=parseFloat(document.getElementById('sim-salaire')?.value)||0;
  const charges=parseFloat(document.getElementById('sim-charges')?.value)||45;
  const autres=parseFloat(document.getElementById('sim-autres')?.value)||0;
  const base=parseFloat(document.getElementById('sim-base')?.value)||151.67;
  const couverture=(parseFloat(document.getElementById('sim-couverture')?.value)||70)/100;
  const plafond=parseInt(document.getElementById('sim-plafond')?.value)||2;
  const annee=document.getElementById('sim-annee')?.value||'';
  const site=document.getElementById('sim-site')?.value||'';
  const poste=''; // tous les postes affichés — pas de filtre poste

  if(!salaire||salaire<100)return;
  const coutCddEtp=salaire*(1+charges/100)+autres;
  const elCout=document.getElementById('sim-cout-etp');
  if(elCout)elCout.textContent=fmtE(coutCddEtp);

  let data=filterByProfile(db.entries);
  if(annee)data=data.filter(e=>e.date.startsWith(annee));
  if(site)data=data.filter(e=>e.site===site);
  if(poste)data=data.filter(e=>e.act===poste);

  const el=document.getElementById('sim-preconisations');
  if(!el)return;
  if(!data.length){el.innerHTML='<p class="empty">Aucune donnée.</p>';return;}

  // ── Agrégation par poste ──────────────────────────────────────────────────
  const postes=[...new Set(data.map(e=>e.act))].filter(Boolean).sort();
  const mois=[...new Set(data.map(e=>e.date.slice(0,7)))].sort();
  const nbMois=mois.length||1;

  const byPoste={};
  postes.forEach(p=>{byPoste[p]={h:0,coutInterim:0,moisActifs:new Set()};});
  data.forEach(e=>{
    const p=e.act;if(!p||!byPoste[p])return;
    byPoste[p].h+=e.h;
    byPoste[p].coutInterim+=coutReel(e);
    byPoste[p].moisActifs.add(e.date.slice(0,7));
  });

  // ── Totaux globaux ────────────────────────────────────────────────────────
  const totH=Object.values(byPoste).reduce((s,v)=>s+v.h,0);
  const totInterim=Object.values(byPoste).reduce((s,v)=>s+v.coutInterim,0);

  // ── Tableau par poste ─────────────────────────────────────────────────────
  let rows='';
  let totCddReco=0, totEco=0;

  postes.forEach(p=>{
    const v=byPoste[p];
    const nbM=v.moisActifs.size||1;
    const etpTotal=v.h/base;
    const etpMoyMois=etpTotal/nbM;

    // ETP à couvrir en CDD (par mois moyen)
    const etpCouvert=etpMoyMois*couverture;
    let nbCdd=Math.floor(etpCouvert);
    if(nbCdd<1&&etpCouvert>=0.5)nbCdd=1;
    nbCdd=Math.min(nbCdd,plafond);

    // Coûts
    const coutCddMois=nbCdd*coutCddEtp;
    const coutCddTotal=coutCddMois*nbM;
    const hCddTotal=nbCdd*base*nbM;
    const hResiduel=Math.max(0,v.h-hCddTotal);
    const coutResiduel=hResiduel>0?v.coutInterim*(hResiduel/v.h):0;
    const coutAvecCdd=coutCddTotal+coutResiduel;
    const eco=v.coutInterim-coutAvecCdd;
    const ecoPct=v.coutInterim>0?(eco/v.coutInterim*100):0;

    totCddReco+=coutAvecCdd;
    totEco+=eco;

    // Préconisation
    let precoTxt, precoCss, precoIcon;
    if(nbCdd<1||etpMoyMois<1){
      precoTxt='Volume insuffisant';precoCss='var(--muted)';precoIcon='⚪';
    } else if(eco<=0){
      precoTxt='Intérim plus économique';precoCss='var(--green)';precoIcon='✅';
    } else if(ecoPct>=30){
      precoTxt=`Recruter ${nbCdd} CDD`;precoCss='var(--red)';precoIcon='🔴';
    } else if(ecoPct>=15){
      precoTxt=`Recruter ${nbCdd} CDD`;precoCss='var(--amber)';precoIcon='🟡';
    } else {
      precoTxt=`Envisager ${nbCdd} CDD`;precoCss='var(--blue)';precoIcon='🔵';
    }

    rows+=`<tr style="border-bottom:1px solid #EEE">
      <td style="padding:10px 14px;font-weight:700;font-size:12px">${p}</td>
      <td style="padding:10px 10px;text-align:center;font-size:11px;color:var(--muted)">${etpMoyMois.toFixed(2)}<br><span style="font-size:9px">/mois</span></td>
      <td style="padding:10px 10px;text-align:center;font-size:11px;color:var(--muted)">${fmtH(v.h)}<br><span style="font-size:9px">${nbM} mois</span></td>
      <td style="padding:10px 10px;text-align:right;font-weight:700;color:var(--blue)">${fmtE(v.coutInterim)}</td>
      <td style="padding:10px 10px;text-align:center;font-size:11px">
        ${nbCdd>0?`<span style="font-weight:700;color:var(--navy)">${nbCdd} CDD</span><br><span style="font-size:9px;color:var(--muted)">${fmtE(coutCddTotal)} + ${fmtE(coutResiduel)} résiduel</span>`:'—'}
      </td>
      <td style="padding:10px 10px;text-align:right;font-weight:800;color:${eco>0?'var(--green)':'var(--danger)'}">
        ${eco>0?'+':''}${fmtE(eco)}<br>
        <span style="font-size:9px;font-weight:400;color:${eco>0?'var(--green)':'var(--danger)'}">${eco>0?'+':''}${ecoPct.toFixed(1)}%</span>
      </td>
      <td style="padding:10px 10px;text-align:center">
        <span style="font-size:11px;font-weight:700;color:${precoCss}">${precoIcon} ${precoTxt}</span>
      </td>
    </tr>`;
  });

  // ── Ligne total ───────────────────────────────────────────────────────────
  const totEcoPct=totInterim>0?(totEco/totInterim*100):0;
  rows+=`<tr style="background:#F0F0EF;border-top:2px solid var(--border);font-weight:700">
    <td style="padding:10px 14px;font-size:11px;text-transform:uppercase;color:var(--muted)">Total</td>
    <td style="padding:10px 10px;text-align:center;font-size:11px;color:var(--muted)">${(totH/base/nbMois).toFixed(2)}/mois</td>
    <td style="padding:10px 10px;text-align:center;font-size:11px;color:var(--muted)">${fmtH(totH)}</td>
    <td style="padding:10px 10px;text-align:right;color:var(--blue)">${fmtE(totInterim)}</td>
    <td style="padding:10px 10px;text-align:center;font-size:11px;color:var(--muted)">${fmtE(totCddReco)}</td>
    <td style="padding:10px 10px;text-align:right;color:${totEco>0?'var(--green)':'var(--danger)'}">
      ${totEco>0?'+':''}${fmtE(totEco)}<br>
      <span style="font-size:9px">${totEco>0?'+':''}${totEcoPct.toFixed(1)}%</span>
    </td>
    <td></td>
  </tr>`;

  // ── Tableau principal ─────────────────────────────────────────────────────
  const tableau=`
    <div style="overflow-x:auto;margin-bottom:20px">
      <table style="width:100%;background:white;border:1.5px solid var(--border);border-radius:8px;border-collapse:collapse">
        <thead>
          <tr style="background:var(--navy)">
            <th style="padding:10px 14px;color:white;font-size:10px;text-align:left;min-width:120px">Poste occupé</th>
            <th style="padding:10px 10px;color:white;font-size:10px;text-align:center;min-width:70px">ETP moy.</th>
            <th style="padding:10px 10px;color:white;font-size:10px;text-align:center;min-width:80px">Heures</th>
            <th style="padding:10px 10px;color:#FCA5A5;font-size:10px;text-align:right;min-width:110px">Coût intérim</th>
            <th style="padding:10px 10px;color:#86C9A8;font-size:10px;text-align:center;min-width:150px">CDD recommandé</th>
            <th style="padding:10px 10px;color:white;font-size:10px;text-align:right;min-width:100px">Économie</th>
            <th style="padding:10px 10px;color:white;font-size:10px;text-align:center;min-width:160px">Préconisation</th>
          </tr>
        </thead>
        <tbody>${rows}</tbody>
      </table>
    </div>`;

  // ── Détail mensuel par poste ──────────────────────────────────────────────
  let detailHtml='';
  postes.forEach(p=>{
    const v=byPoste[p];
    const nbM=v.moisActifs.size||1;
    const etpMoyMois=v.h/base/nbM;
    if(etpMoyMois<1)return; // pas de détail si volume insuffisant

    const etpCouvert=etpMoyMois*couverture;
    let nbCdd=Math.floor(etpCouvert);
    if(nbCdd<1&&etpCouvert>=0.5)nbCdd=1;
    nbCdd=Math.min(nbCdd,plafond);
    if(nbCdd<1)return;

    const eco=v.coutInterim-(nbCdd*coutCddEtp*nbM + Math.max(0,v.h-nbCdd*base*nbM)/v.h*v.coutInterim);
    if(eco<=0)return;

    // Tableau mensuel
    const byMois={};
    mois.forEach(m=>{byMois[m]={h:0,cout:0};});
    data.filter(e=>e.act===p).forEach(e=>{
      const m=e.date.slice(0,7);
      if(byMois[m]){byMois[m].h+=e.h;byMois[m].cout+=coutReel(e);}
    });

    let moisRows=mois.map(m=>{
      const mv=byMois[m];
      if(!mv||mv.h<=0)return`<tr><td style="padding:5px 10px;font-size:11px;color:var(--muted)">${moisLabel(m)}</td><td colspan="5" style="text-align:center;color:#CCC;font-size:11px">—</td></tr>`;
      const etpM=mv.h/base;
      const etpC=etpM*couverture;
      let nCdd=Math.floor(etpC);if(nCdd<1&&etpC>=0.5)nCdd=1;nCdd=Math.min(nCdd,plafond);
      const cddCout=nCdd*coutCddEtp;
      const hRes=Math.max(0,mv.h-nCdd*base);
      const cRes=hRes>0?mv.cout*(hRes/mv.h):0;
      const ecoM=mv.cout-(cddCout+cRes);
      return`<tr style="border-bottom:1px solid #EEE">
        <td style="padding:5px 10px;font-size:11px;font-weight:600">${moisLabel(m)}</td>
        <td style="padding:5px 8px;text-align:center;font-size:11px">${etpM.toFixed(2)}</td>
        <td style="padding:5px 8px;text-align:right;font-size:11px;color:var(--blue)">${fmtE(mv.cout)}</td>
        <td style="padding:5px 8px;text-align:center;font-size:11px">${nCdd>0?`${nCdd} CDD`:'—'}</td>
        <td style="padding:5px 8px;text-align:right;font-size:11px;font-weight:700;color:${ecoM>0?'var(--green)':'var(--danger)'}">${ecoM>0?'+':''}${fmtE(ecoM)}</td>
        <td style="padding:5px 8px;text-align:center">
          <div style="height:12px;background:#F0F0EF;border-radius:3px;overflow:hidden;display:flex;min-width:80px">
            <div style="width:${Math.min(Math.round(cddCout/mv.cout*100),100)}%;background:var(--green);height:100%"></div>
            <div style="width:${Math.min(Math.round(cRes/mv.cout*100),100)}%;background:var(--amber);height:100%"></div>
          </div>
        </td>
      </tr>`;
    }).join('');

    detailHtml+=`
      <div style="margin-bottom:14px">
        <div style="font-size:12px;font-weight:700;color:var(--navy);padding:8px 12px;background:#F7F8FF;border:1.5px solid #DBEAFE;border-radius:6px 6px 0 0">
          📋 Détail mensuel — ${p}
          <span style="font-size:10px;font-weight:400;color:var(--muted);margin-left:8px">${nbCdd} CDD recommandés · ${fmtE(coutCddEtp)}/ETP/mois</span>
        </div>
        <div style="overflow-x:auto">
          <table style="width:100%;background:white;border:1.5px solid #DBEAFE;border-top:none;border-collapse:collapse">
            <thead><tr style="background:#EFF6FF">
              <th style="padding:6px 10px;font-size:9px;color:var(--muted);text-align:left">Mois</th>
              <th style="padding:6px 8px;font-size:9px;color:var(--muted);text-align:center">ETP</th>
              <th style="padding:6px 8px;font-size:9px;color:var(--muted);text-align:right">Coût intérim</th>
              <th style="padding:6px 8px;font-size:9px;color:var(--muted);text-align:center">CDD</th>
              <th style="padding:6px 8px;font-size:9px;color:var(--muted);text-align:right">Économie mois</th>
              <th style="padding:6px 8px;font-size:9px;color:var(--muted);text-align:center">CDD/Résiduel</th>
            </tr></thead>
            <tbody>${moisRows}</tbody>
            <tr style="background:#F0F0EF;border-top:2px solid var(--border)">
              <td style="padding:6px 10px;font-size:10px;font-weight:700;color:var(--muted)">Total</td>
              <td style="padding:6px 8px;text-align:center;font-size:11px;font-weight:700">${(v.h/base).toFixed(2)}</td>
              <td style="padding:6px 8px;text-align:right;font-size:11px;font-weight:700;color:var(--blue)">${fmtE(v.coutInterim)}</td>
              <td style="padding:6px 8px;text-align:center;font-size:10px">${nbCdd} × ${nbM} mois</td>
              <td style="padding:6px 8px;text-align:right;font-size:11px;font-weight:700;color:${eco>0?'var(--green)':'var(--danger)'}">${eco>0?'+':''}${fmtE(eco)}</td>
              <td></td>
            </tr>
          </table>
        </div>
      </div>`;
  });

  // ── Légende couleurs barre ────────────────────────────────────────────────
  const legende=`<div style="display:flex;gap:12px;font-size:9px;color:var(--muted);margin-bottom:8px">
    <span><span style="display:inline-block;width:10px;height:10px;background:var(--green);border-radius:2px;margin-right:3px"></span>CDD fixe</span>
    <span><span style="display:inline-block;width:10px;height:10px;background:var(--amber);border-radius:2px;margin-right:3px"></span>Intérim résiduel (aléas)</span>
  </div>`;

  // ── Tableau récap par poste ──────────────────────────────────────────────
  const elRecap=document.getElementById('sim-recap-poste');
  if(elRecap){
    const totInterimRecap=Object.values(byPoste).reduce((s,v)=>s+v.coutInterim,0);
    let recapRows='';
    postes.forEach(p=>{
      const v=byPoste[p];
      const nbM=v.moisActifs.size||1;
      const etpMoyMois=v.h/base/nbM;
      const etpCouvert=etpMoyMois*couverture;
      let nbCdd=Math.floor(etpCouvert);
      if(nbCdd<1&&etpCouvert>=0.5)nbCdd=1;
      nbCdd=Math.min(nbCdd,plafond);
      const coutCddTotal=nbCdd*coutCddEtp*nbM;
      const hRes=Math.max(0,v.h-nbCdd*base*nbM);
      const coutRes=hRes>0?v.coutInterim*(hRes/v.h):0;
      const eco=v.coutInterim-(coutCddTotal+coutRes);
      const ecoPct=v.coutInterim>0?(eco/v.coutInterim*100):0;
      let icon,col;
      if(nbCdd<1||etpMoyMois<1){icon='⚪';col='var(--muted)';}
      else if(eco<=0){icon='✅';col='var(--green)';}
      else if(ecoPct>=30){icon='🔴';col='var(--red)';}
      else if(ecoPct>=15){icon='🟡';col='var(--amber)';}
      else{icon='🔵';col='var(--blue)';}
      recapRows+=`<tr style="border-bottom:1px solid #EEE">
        <td style="padding:7px 12px;font-weight:700;font-size:11px">${p}</td>
        <td style="padding:7px 10px;text-align:center;font-size:11px">${etpMoyMois.toFixed(2)}</td>
        <td style="padding:7px 10px;text-align:right;font-size:11px;color:var(--blue)">${fmtE(v.coutInterim)}</td>
        <td style="padding:7px 10px;text-align:center;font-weight:700;font-size:13px">${nbCdd>0?`<span style="color:var(--navy)">${nbCdd}</span>`:'—'}</td>
        <td style="padding:7px 10px;text-align:right;font-weight:700;font-size:11px;color:${eco>0?'var(--green)':'var(--danger)'}">${eco>0?'+':''}${fmtE(eco)}</td>
        <td style="padding:7px 10px;text-align:center;font-size:11px;color:${col}">${icon}</td>
      </tr>`;
    });
    // Ligne total
    const totEcoRecap=Object.values(byPoste).reduce((s,v)=>{
      const nbM=v.moisActifs.size||1;
      const etpM=v.h/base/nbM;
      const etpC=etpM*couverture;
      let nCdd=Math.floor(etpC);if(nCdd<1&&etpC>=0.5)nCdd=1;nCdd=Math.min(nCdd,plafond);
      const cRes=Math.max(0,v.h-nCdd*base*nbM);
      const coutRes=cRes>0?v.coutInterim*(cRes/v.h):0;
      return s+(v.coutInterim-(nCdd*coutCddEtp*nbM+coutRes));
    },0);
    recapRows+=`<tr style="background:#F0F0EF;border-top:2px solid var(--border);font-weight:700">
      <td style="padding:7px 12px;font-size:10px;text-transform:uppercase;color:var(--muted)">Total</td>
      <td></td>
      <td style="padding:7px 10px;text-align:right;color:var(--blue)">${fmtE(totInterimRecap)}</td>
      <td></td>
      <td style="padding:7px 10px;text-align:right;color:${totEcoRecap>0?'var(--green)':'var(--danger)'}">${totEcoRecap>0?'+':''}${fmtE(totEcoRecap)}</td>
      <td></td>
    </tr>`;
    elRecap.innerHTML=`<table style="width:100%;background:white;border:1.5px solid var(--border);border-radius:8px;border-collapse:collapse">
      <thead><tr style="background:var(--navy)">
        <th style="padding:8px 12px;color:white;font-size:10px;text-align:left">Poste occupé</th>
        <th style="padding:8px 10px;color:white;font-size:10px;text-align:center">ETP moy./mois</th>
        <th style="padding:8px 10px;color:white;font-size:10px;text-align:right">Coût intérim</th>
        <th style="padding:8px 10px;color:white;font-size:10px;text-align:center">CDD envisageables</th>
        <th style="padding:8px 10px;color:white;font-size:10px;text-align:right">Économie estimée</th>
        <th style="padding:8px 10px;color:white;font-size:10px;text-align:center">Niveau</th>
      </tr></thead>
      <tbody>${recapRows}</tbody>
    </table>`;
  }

  el.innerHTML=tableau+(detailHtml?`<div class="ssub" style="margin-top:4px">Détail mensuel par poste</div>${legende}${detailHtml}`:'');
}

