const _origApplyProfile=typeof applyProfile==='function'?applyProfile:null;

function updateUserPwd(idx,v){const users=loadUsers();if(users[idx])users[idx].pwd=v;saveUsers(users);}
function addSiteExtra(idx,sel){
  const s=sel.value;if(!s)return;
  const users=loadUsers();
  if(!users[idx].sitesExtra)users[idx].sitesExtra=[];
  if(!users[idx].sitesExtra.includes(s))users[idx].sitesExtra.push(s);
  saveUsers(users);sel.value='';renderParams();
}
function removeSiteExtra(idx,s){
  const users=loadUsers();
  if(users[idx].sitesExtra)users[idx].sitesExtra=users[idx].sitesExtra.filter(x=>x!==s);
  saveUsers(users);renderParams();
}
function addInterimToWeek(){
  const agRaw=document.getElementById('f-agence').value.trim();
  const agAutre=document.getElementById('f-agence-autre')?.value?.trim()||'';
  const ag=agRaw==='Autre'&&agAutre?agAutre:(agRaw==='Autre'?'':agRaw);
  if(agRaw==='Autre'&&!agAutre){showAddAlert("Merci de préciser le nom de l'agence.",'err');return;}
  const nom=document.getElementById('f-nom').value.trim();
  let taux=parseFloat(document.getElementById('f-taux').value)||0;
  if(!ag){showAddAlert('Merci de sélectionner une agence d\'intérim.','err');return;}
  if(!nom){showAddAlert('Merci de saisir le nom.','err');return;}
  if(!taux){
    // Chercher dans le mémo
    const memoKey=ag+'|'+nom;
    if(db.memo&&db.memo[memoKey]&&db.memo[memoKey].taux)taux=db.memo[memoKey].taux;
    else taux=12.09; // taux CCN Logistique par défaut
  }
  if(calRows.find(r=>r.nom.toLowerCase()===nom.toLowerCase())){showAddAlert(`${nom} est déjà dans la grille.`,'warn');return;}
  const id=genId();const actGlobal='';
  calRows.push({nom,agence:ag,taux,act:actGlobal||'',id});calState[id]={};
  memoInterim(ag,nom,taux);save();
  document.getElementById('f-nom').value='';document.getElementById('f-taux').value='';
  document.getElementById('hint-new').style.display='none';document.getElementById('ac-dropdown').style.display='none';
  renderMemoZone();render();showAddAlert(`${nom} ajouté(e).`,'ok');
}
function memoInterim(ag,nom,taux){if(!db.memo[ag])db.memo[ag]=[];const idx=db.memo[ag].findIndex(i=>i.nom.toLowerCase()===nom.toLowerCase());if(idx>=0)db.memo[ag][idx].taux=taux;else db.memo[ag].push({nom,taux});}
function renderMemoZone(){const ag=document.getElementById('f-agence').value;const zone=document.getElementById('memo-zone');if(!ag||!(db.memo[ag]||[]).length){zone.innerHTML='';return;}const list=db.memo[ag];zone.innerHTML=`<div class="ag-memo"><div class="ag-memo-title"><span class="badge b-ag">${ag}</span><span style="font-size:10px;color:var(--muted)">${list.length} mémorisé(s) — cliquez pour sélectionner</span></div><div class="ag-chips">${list.map(i=>`<span class="ag-chip" onclick="acSelect('${i.nom.replace(/'/g,"\\'")}',${i.taux||0})">${i.nom} <span style="font-size:9px;color:var(--muted)">${i.taux?i.taux.toFixed(2)+' €/h':''}</span><button class="chip-del" onclick="event.stopPropagation();delMemo('${ag}','${i.nom.replace(/'/g,"\\'")}')">×</button></span>`).join('')}</div>`;}
function onNomInput(){const ag=document.getElementById('f-agence').value;const val=document.getElementById('f-nom').value;const trim=val.trim();const drop=document.getElementById('ac-dropdown');acIndex=-1;if(!ag||!trim){drop.style.display='none';document.getElementById('hint-new').style.display='none';return;}const known=db.memo[ag]||[];const matches=known.filter(i=>i.nom.toLowerCase().startsWith(trim.toLowerCase()));if(matches.length){drop.innerHTML=matches.map((i,idx)=>`<div class="ac-item" data-nom="${i.nom.replace(/"/g,'&quot;')}" data-taux="${i.taux||0}" onmousedown="acSelect('${i.nom.replace(/'/g,"\\'")}',${i.taux||0})" onmouseover="acHover(${idx})">${i.nom.slice(0,trim.length)}<strong style="color:var(--red)">${i.nom.slice(trim.length)}</strong><span style="font-size:10px;color:var(--muted);margin-left:6px">${i.taux?i.taux.toFixed(2)+' €/h':''}</span>`).join('');drop.style.display='block';}else drop.style.display='none';const exact=known.find(i=>i.nom.toLowerCase()===trim.toLowerCase());if(exact){document.getElementById('f-taux').value=exact.taux||'';document.getElementById('hint-new').style.display='none';}else{document.getElementById('hint-new').style.display=trim.length>0?'block':'none';}}
function acSelect(nom,taux){document.getElementById('f-nom').value=nom;document.getElementById('f-taux').value=taux||'';document.getElementById('hint-new').style.display='none';document.getElementById('ac-dropdown').style.display='none';acIndex=-1;}
function acHover(idx){acIndex=idx;document.querySelectorAll('.ac-item').forEach((el,i)=>el.style.background=i===idx?'#FFF0EE':'');}
function onNomKey(e){const drop=document.getElementById('ac-dropdown');const items=drop.querySelectorAll('.ac-item');if(!items.length)return;if(e.key==='ArrowDown'){e.preventDefault();acIndex=Math.min(acIndex+1,items.length-1);items.forEach((el,i)=>el.style.background=i===acIndex?'#FFF0EE':'');}else if(e.key==='ArrowUp'){e.preventDefault();acIndex=Math.max(acIndex-1,0);items.forEach((el,i)=>el.style.background=i===acIndex?'#FFF0EE':'');}else if(e.key==='Enter'||e.key==='Tab'){if(acIndex>=0&&items[acIndex]){e.preventDefault();const it=items[acIndex];acSelect(it.dataset.nom,parseFloat(it.dataset.taux)||0);}}else if(e.key==='Escape'){drop.style.display='none';acIndex=-1;}}
function delMemo(ag,nom){if(!db.memo[ag])return;db.memo[ag]=db.memo[ag].filter(i=>i.nom!==nom);save();renderMemoZone();}
function getS(id,day){return(calState[id]&&calState[id][day])||null;}
function setS(id,day,val){if(!calState[id])calState[id]={};calState[id][day]=val;}
function getRowActOpts(sel){return'<option value="">— Poste —</option>'+db.acts.map(a=>`<option${a===sel?' selected':''}>${a}</option>`).join('');}
function onRowActChange(id,sel){const row=calRows.find(r=>r.id==id);if(row)row.act=sel.value;}
function applyGlobalAct(){}
