function renderCoeffParPoste(){
  const tbody=document.getElementById('cfg-coeff-tbody');
  if(!tbody)return;
  const data=db.coeffParPoste||COEFF_PDF_DEFAULT;
  const postes=Object.keys(COEFF_PDF_DEFAULT);

  // Déterminer le type (sédentaire/roulant) par le nom du poste
  const isRoulant=p=>/(roulant|chauffeur|livreur)/i.test(p);

  tbody.innerHTML=postes.map((p,idx)=>{
    const bg=idx%2===0?'white':'#FAFAFA';
    const agCoeffs=data[p]||COEFF_PDF_DEFAULT[p]||{};
    const typeBadge=isRoulant(p)
      ?'<span style="font-size:9px;background:#FEF3C7;color:#92400E;padding:1px 5px;border-radius:3px">🚗 Roulant</span>'
      :'<span style="font-size:9px;background:#EFF6FF;color:#1E40AF;padding:1px 5px;border-radius:3px">🏢 Sédent.</span>';
    const cells=AGENCES_COEFF.map(ag=>{
      const def=COEFF_PDF_DEFAULT[p]?.[ag];
      const cur=agCoeffs[ag];
      const d=(cur?.delegation??def?.delegation??'');
      const id_d=`coeff_${idx}_${ag.replace(/[^a-zA-Z0-9]/g,'_')}_d`;
      return `<td style="padding:4px 8px;text-align:center">
        <input type="text" id="${id_d}" value="${d}"
          style="width:56px;height:26px;font-size:12px;font-weight:700;text-align:center;border:1px solid var(--border);border-radius:3px;background:${def?.delegation&&d!=def.delegation?'#FFF9C4':'white'}"/>
      </td>`;
    }).join('');
    return `<tr style="background:${bg};border-bottom:1px solid #EEE">
      <td style="padding:7px 12px;font-size:11px;font-weight:600">${p}</td>
      <td style="padding:7px 8px;text-align:center">${typeBadge}</td>
      ${cells}
    </tr>`;
  }).join('');
}

function saveCoeffParPoste(){
  const postes=Object.keys(COEFF_PDF_DEFAULT);
  if(!db.coeffParPoste)db.coeffParPoste={};
  postes.forEach((p,idx)=>{
    if(!db.coeffParPoste[p])db.coeffParPoste[p]={};
    AGENCES_COEFF.forEach(ag=>{
      const id_d=`coeff_${idx}_${ag.replace(/[^a-zA-Z0-9]/g,'_')}_d`;
      const d=parseFloat(document.getElementById(id_d)?.value);
      if(!db.coeffParPoste[p][ag])db.coeffParPoste[p][ag]={};
      if(!isNaN(d)&&d>0)db.coeffParPoste[p][ag].delegation=d;
    });
  });
  save();
  const msg=document.getElementById('coeff-poste-msg');
  if(msg){msg.style.display='inline';setTimeout(()=>msg.style.display='none',2500);}
  renderCoeffParPoste();
}

function resetCoeffParPoste(){
  db.coeffParPoste=JSON.parse(JSON.stringify(COEFF_PDF_DEFAULT));
  save();renderCoeffParPoste();
  const msg=document.getElementById('coeff-poste-msg');
  if(msg){msg.style.display='inline';msg.textContent='Valeurs PDF restaurées ✓';setTimeout(()=>{msg.style.display='none';msg.textContent='Enregistré ✓';},2500);}
}

// Fonction pour obtenir le coeff réel d'une entrée (poste + agence)
function getCoeffForEntry(e){
  const ag=e.agence, act=e.act||'';
  // Chercher dans coeffParPoste (correspondance partielle)
  const data=db.coeffParPoste||COEFF_PDF_DEFAULT;
  const postes=Object.keys(data);
  // Correspondance poste Distritec → poste PDF
  const POSTE_MAP={
    'Manutentionnaire':["Manutentionnaire / S\u00e9dentaire"],
    'Agent de quai / Cariste CACES 1':["Magasinier / Agent de quai / Cariste CACES 1 / S\u00e9dentaire"],
    'Cariste CACES 3-5':["Cariste CACES 3 et 5 / S\u00e9dentaire"],
    'Chef équipe de quai':["Chef \u00e9quipe de quai / S\u00e9dentaire"],
    'Aide livreur / Livreur':["Aide livreur / Livreur / Roulant"],
    'Chauffeur VL':["Chauffeur Livreur VL / Roulant"],
    'Chauffeur PL (< 11t)':["Chauffeur PL / Roulant (>3,5t \u00e0 11t)"],
    'Chauffeur PL (11-19t)':["Chauffeur PL / Roulant (>11t \u00e0 19t)"],
    'Chauffeur PL (> 19t)':["Chauffeur PL / Roulant (>19t)"],
    'Employé administratif':["Employ\u00e9 administratif (op\u00e9rateur saisie / assistant)"],
    'Employé administratif senior':["Employ\u00e9 administratif (comptable / RH / direction)"]
  };
  const pdfPostes=POSTE_MAP[act]||[];
  for(const pp of pdfPostes){
    if(data[pp]&&data[pp][ag]!=null){
      return data[pp][ag].delegation||db.coeff||2;
    }
  }
  // Fallback coeffAgences puis coeff global
  if(db.coeffAgences&&db.coeffAgences[ag]!=null)return db.coeffAgences[ag];
  return db.coeff||2;
}

function updateRowTaux(id,val){
  const taux=parseFloat(val);
  if(isNaN(taux)||taux<=0)return;
  const row=calRows.find(r=>r.id===id);
  if(!row)return;
  row.taux=taux;
  // Mettre à jour le mémo
  memoInterim(row.agence,row.nom,taux);
  save();
  render();
}
function getTauxForMois(moisKey){
  const tm=db.tauxMensuels||{};
  if(tm[moisKey])return{tauxTR:tm[moisKey].tauxTR||9.50,panierRepas:tm[moisKey].panierRepas||15.20};
  return{tauxTR:db.tauxTR||9.50,panierRepas:db.panierRepas||15.20};
}
function renderTauxMensuels(){
  const tbody=document.getElementById('cfg-taux-tbody');if(!tbody)return;
  const today=new Date();const mois=[];
  for(let i=-6;i<=6;i++){
    const d=new Date(today.getFullYear(),today.getMonth()+i,1);
    mois.push(d.getFullYear()+'-'+String(d.getMonth()+1).padStart(2,'0'));
  }
  const tm=db.tauxMensuels||{};
  tbody.innerHTML=mois.map(m=>{
    const v=tm[m]||{};const trV=v.tauxTR!=null?v.tauxTR:'';const pV=v.panierRepas!=null?v.panierRepas:'';
    const hasVal=trV!==''||pV!=='';
    return`<tr style="border-bottom:1px solid #EEE;background:${hasVal?'#FFFBEB':'white'}">
      <td style="padding:6px 14px;font-weight:${hasVal?700:400}">${moisLabel(m)}${hasVal?'<span style="font-size:9px;background:var(--amber);color:white;padding:1px 4px;border-radius:3px;margin-left:6px">spécifique</span>':''}</td>
      <td style="padding:5px 12px;text-align:center"><input type="text" id="tm-tr-${m}" value="${trV}" placeholder="${db.tauxTR||9.50}" style="width:70px;height:26px;font-size:12px;font-weight:700;text-align:center;border:1px solid var(--border);border-radius:3px"/></td>
      <td style="padding:5px 12px;text-align:center"><input type="text" id="tm-pan-${m}" value="${pV}" placeholder="${db.panierRepas||15.20}" style="width:70px;height:26px;font-size:12px;font-weight:700;text-align:center;border:1px solid var(--border);border-radius:3px"/></td>
    </tr>`;
  }).join('');
}
function saveTauxMensuels(){
  if(!db.tauxMensuels)db.tauxMensuels={};
  document.querySelectorAll('[id^="tm-tr-"]').forEach(el=>{
    const m=el.id.replace('tm-tr-','');
    const tr=parseFloat(el.value),pan=parseFloat(document.getElementById('tm-pan-'+m)?.value);
    if((!isNaN(tr)&&tr>0)||(!isNaN(pan)&&pan>0)){
      if(!db.tauxMensuels[m])db.tauxMensuels[m]={};
      if(!isNaN(tr)&&tr>0)db.tauxMensuels[m].tauxTR=tr;
      if(!isNaN(pan)&&pan>0)db.tauxMensuels[m].panierRepas=pan;
    }else delete db.tauxMensuels[m];
  });
  save();
  const msg=document.getElementById('taux-mens-msg');
  if(msg){msg.style.display='inline';setTimeout(()=>msg.style.display='none',2500);}
  renderTauxMensuels();
}
function toggleEvoDetail(rowId){
  const row=document.getElementById(rowId);
  const btn=document.getElementById(rowId+'-btn');
  if(!row)return;
  const open=row.style.display!=='none'&&row.style.display!=='';
  row.style.display=open?'none':'table-row';
  if(btn)btn.style.transform=open?'':'rotate(90deg)';
}
function saveFinancial(){
  const coeff=parseFloat(document.getElementById('cfg-coeff')?.value);
  if(!isNaN(coeff)&&coeff>0)db.coeff=coeff;
  save();renderParams();
}

// Sauvegarde immédiate avant fermeture/rechargement pour ne pas perdre de données
window.addEventListener('beforeunload',()=>{
  if(_saveTimer){clearTimeout(_saveTimer);_saveTimer=null;
    navigator.sendBeacon('/api/data',new Blob([JSON.stringify(db)],{type:'application/json'}));}
});

// Restauration automatique de session au chargement de la page
(async function restoreSession(){
  try{
    const r=await fetch('/api/me');
    if(r.ok){
      const{user}=await r.json();
      CURRENT={...user};
      applyProfile();
      try{await fetchUsers();}catch(e){console.error('fetchUsers:',e);}
      try{await initApp();}catch(e){console.error('initApp:',e);}
      document.getElementById('login-overlay').style.display='none';
      return;
    }
  }catch(e){}
  // Pas de session valide : le formulaire de connexion reste visible
  document.getElementById('login-overlay').style.display='flex';
})();
